   1→/**
   2→ * PianoQuest Live — Express + WebSocket server with Gemini Live API.
   3→ *
   4→ * Uses @google/genai SDK live.connect() for Gemini Live sessions.
   5→ */
   6→
   7→import express from "express";
   8→import { createServer } from "http";
   9→import path from "path";
  10→import fs from "fs";
  11→import { WebSocketServer, WebSocket } from "ws";
  12→import type { IncomingMessage } from "http";
  13→import { GoogleGenAI, Modality, type Session } from "@google/genai";
  14→import {
  15→  LIVE_MODEL,
  16→  STORYTELLER_INSTRUCTION,
  17→  buildToolDeclarations,
  18→  executeToolLocally,
  19→  toolCallToVisualEvent,
  20→} from "./agent.js";
  21→
  22→const APP_NAME = "pianoquest";
  23→const STATIC_DIR = path.join(__dirname, "..", "..", "static");
  24→const SHEETS_DIR = path.join(__dirname, "..", "..", "sheets");
  25→
  26→
  27→const NOTE_NAMES = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"];
  28→
  29→function midiNoteName(note: number): string {
  30→  const octave = Math.floor(note / 12) - 1;
  31→  return `${NOTE_NAMES[note % 12]}${octave}`;
  32→}
  33→
  34→function describeMidiSnapshot(
  35→  msg: Record<string, unknown>,
  36→): string | null {
  37→  const recentNotes = (msg.recent_notes as Array<Record<string, unknown>>) ?? [];
  38→  const activeNotes = (msg.active_notes as Array<Record<string, unknown>>) ?? [];
  39→  const detectedTechniques = (msg.detected_techniques as unknown[]) ?? [];
  40→  const pedalDown = Boolean(msg.pedal_down);
  41→  const bpm = msg.bpm as number | undefined;
  42→  const score = msg.score as number | undefined;
  43→
  44→  const noteBits: string[] = [];
  45→  for (const item of recentNotes.slice(0, 8)) {
  46→    const note = item.note as number | undefined;
  47→    const velocity = item.velocity as number | undefined;
  48→    if (typeof note === "number") {
  49→      noteBits.push(
  50→        typeof velocity === "number"
  51→          ? `${midiNoteName(note)}@${velocity}`
  52→          : midiNoteName(note)
  53→      );
  54→    }
  55→  }
  56→
  57→  const activeBits: string[] = [];
  58→  for (const item of activeNotes.slice(0, 8)) {
  59→    const note = item.note as number | undefined;
  60→    const velocity = item.velocity as number | undefined;
  61→    if (typeof note === "number") {
  62→      activeBits.push(
  63→        typeof velocity === "number"
  64→          ? `${midiNoteName(note)}@${velocity}`
  65→          : midiNoteName(note)
  66→      );
  67→    }
  68→  }
  69→
  70→  const hasPerformanceSignal = recentNotes.length > 0 || activeNotes.length > 0 || pedalDown;
  71→  if (!hasPerformanceSignal) return null;
  72→
  73→  const details: string[] = [];
  74→  if (noteBits.length > 0) details.push("recent notes: " + noteBits.join(", "));
  75→  if (activeBits.length > 0) details.push("currently held: " + activeBits.join(", "));
  76→  details.push(pedalDown ? "sustain pedal is down" : "sustain pedal is up");
  77→  if (bpm) details.push(`target tempo ${bpm} BPM`);
  78→  if (score !== undefined) details.push(`current technique score ${score}`);
  79→  if (detectedTechniques.length > 0) {
  80→    details.push(
  81→      "detected techniques: " + detectedTechniques.slice(0, 6).map(String).join(", ")
  82→    );
  83→  }
  84→
  85→  if (details.length === 0) return null;
  86→
  87→  return (
  88→    "[MIDI snapshot] " +
  89→    details.join(". ")
  90→  );
  91→}
  92→
  93→// =========================================================================
  94→// Spectator broadcasting — spectators receive all output but send nothing
  95→// =========================================================================
  96→
  97→const spectators = new Set<WebSocket>();
  98→
  99→function broadcastSpectators(data: Buffer | string, binary = false) {
 100→  for (const s of spectators) {
 101→    if (s.readyState === WebSocket.OPEN) {
 102→      try { s.send(data, { binary }); } catch {}
 103→    }
 104→  }
 105→}
 106→
 107→// =========================================================================
 108→// Device management types
 109→// =========================================================================
 110→
 111→interface DeviceRoles {
 112→  mic: boolean;
 113→  camera: boolean;
 114→  midi: boolean;
 115→}
 116→
 117→interface Device {
 118→  id: string;
 119→  ws: WebSocket;
 120→  name: string;
 121→  deviceType: "desktop" | "tablet" | "phone" | "unknown";
 122→  isPrimary: boolean;
 123→  roles: DeviceRoles;
 124→  connectedAt: number;
 125→}
 126→
 127→interface RoomSession {
 128→  sendRealtimeInput: (input: any) => void;
 129→  sendClientContent: (content: any) => void;
 130→  primaryWs: WebSocket;
 131→  /** All devices in this room */
 132→  devices: Map<string, Device>;
 133→  /** Accumulated MIDI notes for periodic Gemini snapshots */
 134→  midiBuffer: Array<{ note: number; velocity: number; event: string; timestampMs: number }>;
 135→  midiFlushTimer: ReturnType<typeof setTimeout> | null;
 136→  cameraEnabled: boolean;
 137→  bothHandsDetected: boolean;
 138→  _lastGeminiFrame: number;
 139→  /** Latest MIDI summary — injected when user speaks, not sent independently */
 140→  lastMidiSummary: string | null;
 141→  /** Current session settings (scale, bpm, timeSignature) for spectator sync */
 142→  sessionSettings: { scale: string; bpm: number; timeSignature: string };
 143→}
 144→
 145→const rooms = new Map<string, RoomSession>();
 146→
 147→function generateRoomCode(): string {
 148→  const chars = "REDACTED";
 149→  let code = "";
 150→  const arr = new Uint8Array(4);
 151→  require("crypto").randomFillSync(arr);
 152→  for (let i = 0; i < 4; i++) {
 153→    code += chars[arr[i] % chars.length];
 154→  }
 155→  return code;
 156→}
 157→
 158→function randomHex(bytes: number): string {
 159→  const arr = new Uint8Array(bytes);
 160→  require("crypto").randomFillSync(arr);
 161→  return Buffer.from(arr).toString("hex");
 162→}
 163→
 164→// =========================================================================
 165→// Device detection from User-Agent
 166→// =========================================================================
 167→
 168→function detectDeviceType(req: IncomingMessage): "desktop" | "tablet" | "phone" | "unknown" {
 169→  const ua = (req.headers["user-agent"] || "").toLowerCase();
 170→  if (ua.includes("ipad") || (ua.includes("android") && !ua.includes("mobile"))) return "tablet";
 171→  if (ua.includes("iphone") || ua.includes("android")) return "phone";
 172→  if (ua.includes("windows") || ua.includes("macintosh") || ua.includes("linux")) return "desktop";
 173→  return "unknown";
 174→}
 175→
 176→function deviceTypeIcon(type: string): string {
 177→  switch (type) {
 178→    case "desktop": return "💻";
 179→    case "tablet": return "📱";
 180→    case "phone": return "📷";
 181→    default: return "🔲";
 182→  }
 183→}
 184→
 185→function deviceTypeName(type: string): string {
 186→  switch (type) {
 187→    case "desktop": return "Desktop";
 188→    case "tablet": return "Tablet";
 189→    case "phone": return "Phone";
 190→    default: return "Device";
 191→  }
 192→}
 193→
 194→// =========================================================================
 195→// Room broadcasting — send to all devices in a room + spectators
 196→// =========================================================================
 197→
 198→function broadcastToRoom(room: RoomSession, data: Buffer | string, binary = false) {
 199→  for (const device of room.devices.values()) {
 200→    if (device.ws.readyState === WebSocket.OPEN) {
 201→      try { device.ws.send(data, { binary }); } catch {}
 202→    }
 203→  }
 204→  broadcastSpectators(data, binary);
 205→}
 206→
 207→function sendDeviceList(room: RoomSession) {
 208→  const list = Array.from(room.devices.values()).map((d) => ({
 209→    id: d.id,
 210→    name: d.name,
 211→    deviceType: d.deviceType,
 212→    isPrimary: d.isPrimary,
 213→    roles: { ...d.roles },
 214→    connectedAt: d.connectedAt,
 215→  }));
 216→  const msg = JSON.stringify({ type: "device_list", devices: list });
 217→  // Send to all devices so everyone can see the roster
 218→  for (const device of room.devices.values()) {
 219→    if (device.ws.readyState === WebSocket.OPEN) {
 220→      try { device.ws.send(msg); } catch {}
 221→    }
 222→  }
 223→}
 224→
 225→function setDeviceRole(
 226→  room: RoomSession,
 227→  deviceId: string,
 228→  role: keyof DeviceRoles,
 229→  enabled: boolean
 230→) {
 231→  const device = room.devices.get(deviceId);
 232→  if (!device) return;
 233→
 234→  if (enabled) {
 235→    // Exclusive: disable this role on all other devices
 236→    for (const d of room.devices.values()) {
 237→      if (d.id !== deviceId && d.roles[role]) {
 238→        d.roles[role] = false;
 239→        // Notify the device that lost the role
 240→        if (d.ws.readyState === WebSocket.OPEN) {
 241→          try {
 242→            d.ws.send(JSON.stringify({
 243→              type: "role_assigned",
 244→              roles: { ...d.roles },
 245→            }));
 246→          } catch {}
 247→        }
 248→      }
 249→    }
 250→  }
 251→
 252→  device.roles[role] = enabled;
 253→
 254→  // Notify the device that got/lost the role
 255→  if (device.ws.readyState === WebSocket.OPEN) {
 256→    try {
 257→      device.ws.send(JSON.stringify({
 258→        type: "role_assigned",
 259→        roles: { ...device.roles },
 260→      }));
 261→    } catch {}
 262→  }
 263→
 264→  // Broadcast updated device list
 265→  sendDeviceList(room);
 266→}
 267→
 268→// =========================================================================
 269→// Express + WebSocket server
 270→// =========================================================================
 271→
 272→export function createApp() {
 273→  const app = express();
 274→  const server = createServer(app);
 275→  const wssDialog = new WebSocketServer({ noServer: true });
 276→  const wssSpectator = new WebSocketServer({ noServer: true });
 277→  const wssMidi = new WebSocketServer({ noServer: true });
 278→  const wssSession = new WebSocketServer({ noServer: true });
 279→
 280→  app.get("/health", (_req, res) => {
 281→    res.json({
 282→      status: "ok",
 283→      service: APP_NAME,
 284→      modes: ["storyteller"],
 285→      spectators: spectators.size,
 286→      rooms: rooms.size,
 287→    });
 288→  });
 289→
 290→  app.get("/", (_req, res) => {
 291→    res.sendFile(path.join(STATIC_DIR, "index.html"));
 292→  });
 293→
 294→  app.use("/static", express.static(STATIC_DIR));
 295→  app.use("/sheets", express.static(SHEETS_DIR));
 296→
 297→  // List sheet music files as a tree
 298→  app.get("/api/sheets", (_req, res) => {
 299→    function walkDir(dir: string, prefix: string): any[] {
 300→      const entries: any[] = [];
 301→      if (!fs.existsSync(dir)) return entries;
 302→      for (const name of fs.readdirSync(dir).sort()) {
 303→        const full = path.join(dir, name);
 304→        const rel = prefix ? `${prefix}/${name}` : name;
 305→        const stat = fs.statSync(full);
 306→        if (stat.isDirectory()) {
 307→          entries.push({ name, path: rel, type: "folder", children: walkDir(full, rel) });
 308→        } else if (name.endsWith(".json")) {
 309→          entries.push({ name: name.replace(".json", ""), path: rel, type: "file" });
 310→        }
 311→      }
 312→      return entries;
 313→    }
 314→    res.json(walkDir(SHEETS_DIR, ""));
 315→  });
 316→
 317→  server.on("upgrade", (request: IncomingMessage, socket, head) => {
 318→    const url = new URL(request.url ?? "/", `http://${request.headers.host}`);
 319→    if (url.pathname === "/ws/session") {
 320→      wssSession.handleUpgrade(request, socket, head, (ws) => {
 321→        (ws as any)._req = request;
 322→        (ws as any)._room = url.searchParams.get("room") ?? "";
 323→        (ws as any)._roleHint = url.searchParams.get("role") ?? "";
 324→        wssSession.emit("connection", ws, request);
 325→      });
 326→    } else if (url.pathname === "/ws/dialog") {
 327→      wssDialog.handleUpgrade(request, socket, head, (ws) => {
 328→        wssDialog.emit("connection", ws, request);
 329→      });
 330→    } else if (url.pathname === "/ws/spectator") {
 331→      wssSpectator.handleUpgrade(request, socket, head, (ws) => {
 332→        wssSpectator.emit("connection", ws, request);
 333→      });
 334→    } else if (url.pathname === "/ws/midi") {
 335→      const room = url.searchParams.get("room") ?? "";
 336→      wssMidi.handleUpgrade(request, socket, head, (ws) => {
 337→        (ws as any)._room = room;
 338→        wssMidi.emit("connection", ws, request);
 339→      });
 340→    } else {
 341→      socket.destroy();
 342→    }
 343→  });
 344→
 345→  // -----------------------------------------------------------------
 346→  // /ws/session — Unified device management endpoint
 347→  // -----------------------------------------------------------------
 348→
 349→  wssSession.on("connection", (ws: WebSocket) => {
 350→    const req = (ws as any)._req as IncomingMessage;
 351→    const roomCode = (ws as any)._room as string;
 352→    const roleHint = (ws as any)._roleHint as string;
 353→    const devType = detectDeviceType(req);
 354→
 355→    if (!roomCode) {
 356→      // No room code — this is a new primary device
 357→      handlePrimaryWebSocket(ws, req);
 358→    } else {
 359→      // Room code provided — join as secondary
 360→      const room = rooms.get(roomCode);
 361→      if (!room) {
 362→        console.log(`[${APP_NAME}] Session rejected — room "${roomCode}" not found`);
 363→        ws.send(JSON.stringify({ type: "error", message: `Room "${roomCode}" not found` }));
 364→        ws.close();
 365→        return;
 366→      }
 367→      handleSecondaryWebSocket(ws, room, roomCode, devType, roleHint);
 368→    }
 369→  });
 370→
 371→  // -----------------------------------------------------------------
 372→  // /ws/dialog — Legacy primary endpoint (backwards compat)
 373→  // -----------------------------------------------------------------
 374→
 375→  wssDialog.on("connection", (ws: WebSocket, req: IncomingMessage) => {
 376→    handlePrimaryWebSocket(ws, req);
 377→  });
 378→
 379→  wssSpectator.on("connection", (ws: WebSocket) => {
 380→    spectators.add(ws);
 381→    console.log(`[${APP_NAME}] Spectator connected (total: ${spectators.size})`);
 382→
 383→    // Send immediate status so bridge knows connection is live
 384→    const activeRoom = Array.from(rooms.values())[0];
 385→    ws.send(JSON.stringify({
 386→      type: "spectator_status",
 387→      connected: true,
 388→      spectators: spectators.size,
 389→      activeSession: !!activeRoom,
 390→      room: activeRoom ? Array.from(rooms.keys())[0] : null,
 391→    }));
 392→
 393→    // Send current session settings snapshot so spectator starts with correct values
 394→    if (activeRoom) {
 395→      ws.send(JSON.stringify({ type: "session_settings", ...activeRoom.sessionSettings }));
 396→    }
 397→
 398→    // Keepalive ping every 20s to prevent Cloud Run timeout
 399→    let alive = true;
 400→    const pingInterval = setInterval(() => {
 401→      if (ws.readyState !== WebSocket.OPEN) {
 402→        clearInterval(pingInterval);
 403→        return;
 404→      }
 405→      if (!alive) {
 406→        // Missed pong — connection dead
 407→        ws.terminate();
 408→        return;
 409→      }
 410→      alive = false;
 411→      ws.ping();
 412→    }, 20000);
 413→
 414→    ws.on("pong", () => { alive = true; });
 415→
 416→    // Allow spectators to push session_settings back to the active room
 417→    ws.on("message", (raw: Buffer | string) => {
 418→      try {
 419→        const msg = JSON.parse(typeof raw === "string" ? raw : raw.toString());
 420→        if (msg.type === "session_settings") {
 421→          const room = Array.from(rooms.values())[0];
 422→          if (room) {
 423→            room.sessionSettings = {
 424→              scale: String(msg.scale || room.sessionSettings.scale),
 425→              bpm: Number(msg.bpm) || room.sessionSettings.bpm,
 426→              timeSignature: String(msg.timeSignature || room.sessionSettings.timeSignature),
 427→            };
 428→            console.log(`[${APP_NAME}] Spectator pushed session_settings:`, room.sessionSettings);
 429→            broadcastToRoom(room, JSON.stringify({ type: "session_settings", ...room.sessionSettings }));
 430→          }
 431→        }
 432→      } catch {}
 433→    });
 434→
 435→    ws.on("close", () => {
 436→      clearInterval(pingInterval);
 437→      spectators.delete(ws);
 438→      console.log(`[${APP_NAME}] Spectator disconnected (total: ${spectators.size})`);
 439→    });
 440→    ws.on("error", () => {
 441→      clearInterval(pingInterval);
 442→      spectators.delete(ws);
 443→    });
 444→  });
 445→
 446→  // -----------------------------------------------------------------
 447→  // /ws/midi — Ubuntu bridge forwards MIDI events to Gemini + iPad
 448→  // -----------------------------------------------------------------
 449→
 450→  function flushMidiToGemini(roomSession: RoomSession) {
 451→    if (roomSession.midiBuffer.length === 0) return;
 452→
 453→    const recentNotes = roomSession.midiBuffer
 454→      .filter((m) => m.event === "noteOn")
 455→      .slice(-8)
 456→      .map((m) => ({ note: m.note, velocity: m.velocity }));
 457→
 458→    const activeNotes: Array<{ note: number; velocity: number }> = [];
 459→    const noteOnMap = new Map<number, number>();
 460→    for (const m of roomSession.midiBuffer) {
 461→      if (m.event === "noteOn") {
 462→        noteOnMap.set(m.note, m.velocity);
 463→      } else if (m.event === "noteOff") {
 464→        noteOnMap.delete(m.note);
 465→      }
 466→    }
 467→    for (const [note, velocity] of noteOnMap) {
 468→      activeNotes.push({ note, velocity });
 469→    }
 470→
 471→    const summary = describeMidiSnapshot(
 472→      { recent_notes: recentNotes, active_notes: activeNotes, pedal_down: false },
 473→    );
 474→
 475→    if (summary) {
 476→      roomSession.lastMidiSummary = summary;
 477→      roomSession.sendClientContent({
 478→        turns: [{ role: "user", parts: [{ text: summary }] }],
 479→        turnComplete: false,
 480→      });
 481→    }
 482→
 483→    roomSession.midiBuffer = [];
 484→  }
 485→
 486→  wssMidi.on("connection", (ws: WebSocket) => {
 487→    const room = (ws as any)._room as string;
 488→    const roomSession = rooms.get(room);
 489→    if (!roomSession) {
 490→      console.log(`[${APP_NAME}] MIDI rejected — room "${room}" not found`);
 491→      ws.send(JSON.stringify({ type: "error", message: `Room "${room}" not found` }));
 492→      ws.close();
 493→      return;
 494→    }
 495→
 496→    console.log(`[${APP_NAME}] MIDI bridge connected to room "${room}"`);
 497→    ws.send(JSON.stringify({ type: "midi_connected", room }));
 498→
 499→    ws.on("message", (data: Buffer | string) => {
 500→      if (typeof data !== "string") return;
 501→      try {
 502→        const msg = JSON.parse(data);
 503→        if (msg.type !== "midi") return;
 504→
 505→        // Forward raw MIDI event to all room devices for waterfall rendering
 506→        broadcastToRoom(roomSession, JSON.stringify(msg));
 507→
 508→        // Buffer for Gemini (flush every 2 seconds)
 509→        if (msg.event === "noteOn" || msg.event === "noteOff") {
 510→          roomSession.midiBuffer.push({
 511→            note: msg.note ?? 0,
 512→            velocity: msg.velocity ?? 0,
 513→            event: msg.event,
 514→            timestampMs: msg.timestampMs ?? Date.now(),
 515→          });
 516→
 517→          if (!roomSession.midiFlushTimer) {
 518→            roomSession.midiFlushTimer = setTimeout(() => {
 519→              roomSession.midiFlushTimer = null;
 520→              flushMidiToGemini(roomSession);
 521→            }, 2000);
 522→          }
 523→        }
 524→      } catch {}
 525→    });
 526→
 527→    ws.on("close", () => {
 528→      console.log(`[${APP_NAME}] MIDI bridge disconnected from room "${room}"`);
 529→      if (roomSession.midiFlushTimer) {
 530→        clearTimeout(roomSession.midiFlushTimer);
 531→        roomSession.midiFlushTimer = null;
 532→        flushMidiToGemini(roomSession);
 533→      }
 534→    });
 535→  });
 536→
 537→  return server;
 538→}
 539→
 540→// =========================================================================
 541→// Async WebSocket message generator
 542→// =========================================================================
 543→
 544→async function* wsMessages(
 545→  ws: WebSocket
 546→): AsyncGenerator<Buffer | string, void, undefined> {
 547→  const queue: (Buffer | string)[] = [];
 548→  let resolve: (() => void) | null = null;
 549→  let done = false;
 550→
 551→  ws.on("message", (data: Buffer | string, isBinary: boolean) => {
 552→    // ws library delivers ALL messages as Buffer; use isBinary to distinguish
 553→    const item = isBinary ? data : data.toString();
 554→    queue.push(item);
 555→    if (resolve) {
 556→      resolve();
 557→      resolve = null;
 558→    }
 559→  });
 560→
 561→  ws.on("close", () => {
 562→    done = true;
 563→    if (resolve) {
 564→      resolve();
 565→      resolve = null;
 566→    }
 567→  });
 568→
 569→  ws.on("error", () => {
 570→    done = true;
 571→    if (resolve) {
 572→      resolve();
 573→      resolve = null;
 574→    }
 575→  });
 576→
 577→  while (true) {
 578→    if (queue.length > 0) {
 579→      yield queue.shift()!;
 580→    } else if (done) {
 581→      return;
 582→    } else {
 583→      await new Promise<void>((r) => {
 584→        resolve = r;
 585→      });
 586→    }
 587→  }
 588→}
