 590→// =========================================================================
 591→// Secondary device handler — joins an existing room
 592→// =========================================================================
 593→
 594→async function handleSecondaryWebSocket(
 595→  ws: WebSocket,
 596→  room: RoomSession,
 597→  roomCode: string,
 598→  devType: "desktop" | "tablet" | "phone" | "unknown",
 599→  roleHint: string
 600→) {
 601→  const deviceId = randomHex(4);
 602→  const device: Device = {
 603→    id: deviceId,
 604→    ws,
 605→    name: deviceTypeName(devType),
 606→    deviceType: devType,
 607→    isPrimary: false,
 608→    roles: { mic: false, camera: false, midi: false },
 609→    connectedAt: Date.now(),
 610→  };
 611→
 612→  room.devices.set(deviceId, device);
 613→  console.log(`[${APP_NAME}] Secondary device ${deviceId} (${devType}) joined room "${roomCode}"`);
 614→
 615→  // Keepalive ping every 20s to prevent Cloud Run from killing idle connections
 616→  let secAlive = true;
 617→  const secPingInterval = setInterval(() => {
 618→    if (ws.readyState !== WebSocket.OPEN) { clearInterval(secPingInterval); return; }
 619→    if (!secAlive) { ws.terminate(); return; }
 620→    secAlive = false;
 621→    ws.ping();
 622→  }, 20000);
 623→  ws.on("pong", () => { secAlive = true; });
 624→
 625→  // Send identity to the secondary device
 626→  ws.send(JSON.stringify({
 627→    type: "you_are_secondary",
 628→    room: roomCode,
 629→    deviceId,
 630→    deviceType: devType,
 631→  }));
 632→
 633→  // If role hint provided, auto-assign that role
 634→  if (roleHint === "mic" || roleHint === "midi" || roleHint === "camera") {
 635→    setDeviceRole(room, deviceId, roleHint as keyof DeviceRoles, true);
 636→  }
 637→
 638→  // Broadcast updated device list
 639→  sendDeviceList(room);
 640→
 641→  // Handle incoming messages from secondary
 642→  try {
 643→    for await (const rawMsg of wsMessages(ws)) {
 644→      // Binary = PCM audio (only if this device has mic role)
 645→      if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
 646→        if (!device.roles.mic) continue;
 647→        const data = rawMsg instanceof ArrayBuffer ? new Uint8Array(rawMsg) : rawMsg;
 648→        room.sendRealtimeInput({
 649→          audio: { data: Buffer.from(data).toString("base64"), mimeType: "audio/pcm;rate=16000" },
 650→        });
 651→      } else if (typeof rawMsg === "string") {
 652→        const msg = JSON.parse(rawMsg);
 653→        const msgType = msg.type;
 654→
 655→        if (msgType === "midi_snapshot" && device.roles.midi) {
 656→          const summary = describeMidiSnapshot(msg);
 657→          if (summary) {
 658→            room.lastMidiSummary = summary;
 659→            room.sendClientContent({
 660→              turns: [{ role: "user", parts: [{ text: summary }] }],
 661→              turnComplete: false,
 662→            });
 663→          }
 664→        } else if (msgType === "midi_event" && device.roles.midi) {
 665→          // Forward raw MIDI to all room devices for visualization
 666→          broadcastToRoom(room, JSON.stringify(msg));
 667→        } else if (msgType === "video_frame" && device.roles.camera) {
 668→          // Forward camera JPEG frame to Gemini (throttled 1fps) + broadcast to room (every frame)
 669→          const data = msg.data as string;
 670→          if (data) {
 671→            const now = Date.now();
 672→            if (!room._lastGeminiFrame || now - room._lastGeminiFrame >= 1000) {
 673→              room._lastGeminiFrame = now;
 674→              room.sendRealtimeInput({
 675→                media: { data, mimeType: "image/jpeg" },
 676→              });
 677→            }
 678→            // Send every frame to other devices for smooth preview
 679→            for (const d of room.devices.values()) {
 680→              if (d.id !== deviceId && d.ws.readyState === WebSocket.OPEN) {
 681→                try { d.ws.send(JSON.stringify({ type: "video_frame", data })); } catch {}
 682→              }
 683→            }
 684→          }
 685→        } else if (msgType === "camera_state") {
 686→          room.cameraEnabled = Boolean(msg.enabled);
 687→          broadcastToRoom(room, JSON.stringify({ type: "camera_state", enabled: room.cameraEnabled }));
 688→        } else if (msgType === "hand_state") {
 689→          room.bothHandsDetected = Boolean(msg.bothHands);
 690→          broadcastToRoom(room, JSON.stringify({ type: "hand_state", hands: msg.hands, bothHands: msg.bothHands }));
 691→        } else if (msgType === "text") {
 692→          room.sendClientContent({
 693→            turns: [{ role: "user", parts: [{ text: msg.content as string }] }],
 694→            turnComplete: true,
 695→          });
 696→        } else if (msgType === "user_speech_transcript") {
 697→          // Browser SpeechRecognition transcript — broadcast to all devices
 698→          const text = (msg.text as string || "").trim();
 699→          if (text) {
 700→            broadcastToRoom(room, JSON.stringify({ type: "input_transcript", text }));
 701→          }
 702→        } else if (msgType === "request_role") {
 703→          // Secondary device self-assigns a role
 704→          const role = msg.role as string;
 705→          if (role === "mic" || role === "midi" || role === "camera") {
 706→            setDeviceRole(room, deviceId, role, Boolean(msg.enabled));
 707→            console.log(`[${APP_NAME}] Secondary ${deviceId} self-assigned ${role}=${msg.enabled}`);
 708→          }
 709→        } else if (msgType === "device_info") {
 710→          // Device sends its name
 711→          if (msg.name) device.name = String(msg.name).slice(0, 32);
 712→          sendDeviceList(room);
 713→        } else if (msgType === "close") {
 714→          break;
 715→        }
 716→      }
 717→    }
 718→  } catch (e: any) {
 719→    console.log(`[${APP_NAME}] Secondary ${deviceId} error:`, e?.message);
 720→  } finally {
 721→    clearInterval(secPingInterval);
 722→    room.devices.delete(deviceId);
 723→    console.log(`[${APP_NAME}] Secondary device ${deviceId} disconnected from room "${roomCode}"`);
 724→    sendDeviceList(room);
 725→    try { ws.close(); } catch {}
 726→  }
 727→}
 728→
 729→// =========================================================================
 730→// Primary WebSocket handler — creates Gemini Live session
 731→// =========================================================================
 732→
 733→async function handlePrimaryWebSocket(ws: WebSocket, req: IncomingMessage) {
 734→  const apiKey = process.env.GOOGLE_API_KEY ?? process.env.GEMINI_API_KEY;
 735→  if (!apiKey) {
 736→    ws.send(JSON.stringify({ type: "error", message: "No API key configured" }));
 737→    ws.close();
 738→    return;
 739→  }
 740→
 741→  const sessionId = randomHex(4);
 742→  const roomCode = generateRoomCode();
 743→  let closed = false;
 744→
 745→  // Transcription buffers
 746→  let bufInput = "";
 747→  let bufOutput = "";
 748→
 749→  // Device registration for primary
 750→  const devType = detectDeviceType(req);
 751→  const primaryDeviceId = randomHex(4);
 752→  const primaryDevice: Device = {
 753→    id: primaryDeviceId,
 754→    ws,
 755→    name: deviceTypeName(devType) + " (Primary)",
 756→    deviceType: devType,
 757→    isPrimary: true,
 758→    roles: { mic: true, camera: false, midi: true },
 759→    connectedAt: Date.now(),
 760→  };
 761→
 762→  console.log(`[${APP_NAME}] Primary connected: ${sessionId}, room: ${roomCode}, device: ${primaryDeviceId}`);
 763→
 764→  // ---------------------------------------------------------------------------
 765→  // Gemini Live API via @google/genai SDK
 766→  // ---------------------------------------------------------------------------
 767→  const client = new GoogleGenAI({ apiKey });
 768→  let session: Session;
 769→  let roomSession: RoomSession | null = null;
 770→  let audioMsgCount = 0;
 771→
 772→  const sendAll = (data: Buffer | string, binary = false) => {
 773→    if (roomSession) broadcastToRoom(roomSession, data, binary);
 774→  };
 775→
 776→  try {
 777→    session = await client.live.connect({
 778→      model: LIVE_MODEL,
 779→      config: {
 780→        responseModalities: [Modality.AUDIO],
 781→        systemInstruction: STORYTELLER_INSTRUCTION,
 782→        speechConfig: {
 783→          languageCode: "en-US",
 784→          voiceConfig: {
 785→            prebuiltVoiceConfig: { voiceName: "Puck" },
 786→          },
 787→        },
 788→        outputAudioTranscription: {},
 789→        realtimeInputConfig: {
 790→          automaticActivityDetection: {
 791→            disabled: false,
 792→          },
 793→        },
 794→        tools: buildToolDeclarations() as any,
 795→      },
 796→      callbacks: {
 797→        onopen: () => {
 798→          console.log(`[${APP_NAME}] Gemini Live connected: ${sessionId}`);
 799→          roomSession = {
 800→            sendRealtimeInput: (input: any) => session.sendRealtimeInput(input),
 801→            sendClientContent: (content: any) => session.sendClientContent(content),
 802→            primaryWs: ws,
 803→            devices: new Map(),
 804→            midiBuffer: [],
 805→            midiFlushTimer: null,
 806→            cameraEnabled: false,
 807→            bothHandsDetected: false,
 808→            _lastGeminiFrame: 0,
 809→            lastMidiSummary: null,
 810→            sessionSettings: { scale: "C major", bpm: 90, timeSignature: "4/4" },
 811→          };
 812→          roomSession.devices.set(primaryDeviceId, primaryDevice);
 813→          rooms.set(roomCode, roomSession);
 814→
 815→          ws.send(JSON.stringify({ type: "you_are_primary", room: roomCode, deviceId: primaryDeviceId }));
 816→          ws.send(JSON.stringify({ type: "room_code", room: roomCode }));
 817→          sendDeviceList(roomSession);
 818→
 819→          // No greeting — Gemini stays silent until user speaks
 820→        },
 821→        onerror: (e: unknown) => {
 822→          console.error(`[${APP_NAME}] Gemini error: ${sessionId}`, e);
 823→          try { ws.send(JSON.stringify({ type: "gemini_error", error: String(e) })); } catch {}
 824→        },
 825→        onclose: () => {
 826→          console.error(`[${APP_NAME}] *** Gemini closed: session=${sessionId}`);
 827→          closed = true;
 828→          try { ws.send(JSON.stringify({ type: "gemini_error", code: 1000, reason: "Session ended" })); } catch {}
 829→          try { ws.close(); } catch {}
 830→        },
 831→        onmessage: (msg: unknown) => {
 832→          if (closed || !roomSession) return;
 833→          const message = msg as Record<string, unknown>;
 834→          const msgKeys = Object.keys(message);
 835→
 836→          // Log non-audio messages for debugging
 837→          if (msgKeys.includes("setupComplete")) {
 838→            console.log(`[${APP_NAME}] ${sessionId} setupComplete`);
 839→            return;
 840→          }
 841→
 842→          const serverContent = message.serverContent as Record<string, unknown> | undefined;
 843→          if (serverContent) {
 844→            const modelTurn = serverContent.modelTurn as Record<string, unknown> | undefined;
 845→            if (modelTurn?.parts) {
 846→              const parts = modelTurn.parts as Array<Record<string, unknown>>;
 847→              for (const part of parts) {
 848→                const inlineData = part.inlineData as Record<string, unknown> | undefined;
 849→                if (inlineData?.data) {
 850→                  audioMsgCount++;
 851→                  if (audioMsgCount <= 3) console.log(`[${APP_NAME}] ${sessionId} audio chunk #${audioMsgCount}`);
 852→                  sendAll(Buffer.from(inlineData.data as string, "base64"), true);
 853→                }
 854→                // Tool calls
 855→                const functionCall = part.functionCall as Record<string, unknown> | undefined;
 856→                if (functionCall) {
 857→                  const name = functionCall.name as string;
 858→                  const args = (functionCall.args as Record<string, unknown>) || {};
 859→                  const visualEvent = toolCallToVisualEvent(name, args);
 860→                  if (visualEvent) sendAll(JSON.stringify(visualEvent));
 861→                  const result = executeToolLocally(name, args);
 862→                  const id = functionCall.id as string;
 863→                  session.sendToolResponse({ functionResponses: [{ id, name, response: result }] });
 864→                  console.log(`[${APP_NAME}] ${sessionId} tool: ${name}`);
 865→                }
 866→              }
 867→            }
 868→
 869→            // Transcription
 870→            const outputTranscription = serverContent.outputTranscription as Record<string, unknown> | undefined;
 871→            if (outputTranscription?.text) {
 872→              const text = (outputTranscription.text as string).trim();
 873→              if (text) {
 874→                bufOutput += (bufOutput ? " " : "") + text;
 875→                console.log(`[${APP_NAME}] ${sessionId} OUT: ${text}`);
 876→              }
 877→            }
 878→
 879→            // Turn complete
 880→            if (serverContent.turnComplete) {
 881→              if (bufInput) { sendAll(JSON.stringify({ type: "input_transcript", text: bufInput })); bufInput = ""; }
 882→              if (bufOutput) { sendAll(JSON.stringify({ type: "output_transcript", text: bufOutput })); bufOutput = ""; }
 883→              sendAll(JSON.stringify({ type: "turn_complete" }));
 884→              console.log(`[${APP_NAME}] ${sessionId} turnComplete (audioChunks=${audioMsgCount})`);
 885→            }
 886→
 887→            // Interrupted
 888→            if (serverContent.interrupted) {
 889→              if (bufInput) { sendAll(JSON.stringify({ type: "input_transcript", text: bufInput })); bufInput = ""; }
 890→              if (bufOutput) { sendAll(JSON.stringify({ type: "output_transcript", text: bufOutput })); bufOutput = ""; }
 891→              sendAll(JSON.stringify({ type: "interrupted" }));
 892→              console.log(`[${APP_NAME}] ${sessionId} interrupted`);
 893→            }
 894→          }
 895→
 896→          // toolCallCancellation
 897→          const toolCall = message.toolCall as Record<string, unknown> | undefined;
 898→          if (toolCall?.functionCalls) {
 899→            const functionCalls = toolCall.functionCalls as Array<Record<string, unknown>>;
 900→            for (const fc of functionCalls) {
 901→              const name = fc.name as string;
 902→              const id = fc.id as string;
 903→              const args = (fc.args as Record<string, unknown>) || {};
 904→              const visualEvent = toolCallToVisualEvent(name, args);
 905→              if (visualEvent) sendAll(JSON.stringify(visualEvent));
 906→              const result = executeToolLocally(name, args);
 907→              session.sendToolResponse({ functionResponses: [{ id, name, response: result }] });
 908→              console.log(`[${APP_NAME}] ${sessionId} toolCall: ${name}`);
 909→            }
 910→          }
 911→        },
 912→      },
 913→    });
 914→  } catch (err) {
 915→    console.error(`[${APP_NAME}] Failed to connect Gemini Live:`, err);
 916→    ws.send(JSON.stringify({ type: "error", message: "Failed to connect to Gemini" }));
 917→    ws.close(1011, "Failed to connect to Gemini");
 918→    return;
 919→  }
 920→
 921→  console.log(`[${APP_NAME}] Gemini session ready: ${sessionId}, room: ${roomCode}`);
 922→
 923→  // Keepalive ping every 20s to prevent Cloud Run from killing the connection
 924→  let primaryAlive = true;
 925→  const primaryPingInterval = setInterval(() => {
 926→    if (ws.readyState !== WebSocket.OPEN) { clearInterval(primaryPingInterval); return; }
 927→    if (!primaryAlive) { ws.terminate(); return; }
 928→    primaryAlive = false;
 929→    ws.ping();
 930→  }, 20000);
 931→  ws.on("pong", () => { primaryAlive = true; });
 932→
 933→  // ---------------------------------------------------------------------------
 934→  // Receive from primary client, forward to Gemini
 935→  // ---------------------------------------------------------------------------
 936→  try {
 937→    for await (const rawMsg of wsMessages(ws)) {
 938→      if (closed) break;
 939→
 940→      if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
 941→        if (!primaryDevice.roles.mic) continue;
 942→        const data = rawMsg instanceof ArrayBuffer ? new Uint8Array(rawMsg) : rawMsg;
 943→        session.sendRealtimeInput({
 944→          audio: { data: Buffer.from(data).toString("base64"), mimeType: "audio/pcm;rate=16000" },
 945→        });
 946→      } else if (typeof rawMsg === "string") {
 947→        const msg = JSON.parse(rawMsg);
 948→        const msgType = msg.type;
 949→
 950→
 951→        if (msgType === "text") {
 952→          session.sendClientContent({
 953→            turns: [{ role: "user", parts: [{ text: msg.content }] }],
 954→            turnComplete: true,
 955→          });
 956→        } else if (msgType === "midi_snapshot") {
 957→          // Send MIDI as background context (turnComplete=false = won't trigger response)
 958→          // Also store for when user explicitly asks for analysis
 959→          const summary = describeMidiSnapshot(msg);
 960→          if (summary && roomSession) {
 961→            (roomSession as RoomSession).lastMidiSummary = summary;
 962→            session.sendClientContent({
 963→              turns: [{ role: "user", parts: [{ text: summary }] }],
 964→              turnComplete: false,
 965→            });
 966→          }
 967→        } else if (msgType === "user_speech_transcript") {
 968→          // Browser SpeechRecognition transcript — broadcast to all devices
 969→          const text = (msg.text as string || "").trim();
 970→          if (text && roomSession) {
 971→            broadcastToRoom(roomSession, JSON.stringify({ type: "input_transcript", text }));
 972→          }
 973→        } else if (msgType === "set_mode") {
 974→          // Single agent — mode is always storyteller
 975→        } else if (msgType === "midi_event") {
 976→          // Broadcast MIDI events to all room devices + spectators for visualization
 977→          if (roomSession) {
 978→            broadcastToRoom(roomSession, JSON.stringify(msg));
 979→          } else {
 980→            broadcastSpectators(JSON.stringify(msg));
 981→          }
 982→        } else if (msgType === "video_frame" && primaryDevice.roles.camera) {
 983→          const data = msg.data as string;
 984→          if (data) {
 985→            session.sendRealtimeInput({
 986→              media: { data, mimeType: "image/jpeg" },
 987→            });
 988→          }
 989→        } else if (msgType === "camera_state") {
 990→          const rs = roomSession as RoomSession | null;
 991→          if (rs) {
 992→            rs.cameraEnabled = Boolean(msg.enabled);
 993→            broadcastToRoom(rs, JSON.stringify({ type: "camera_state", enabled: rs.cameraEnabled }));
 994→          }
 995→        } else if (msgType === "session_settings") {
 996→          const rs = roomSession as RoomSession | null;
 997→          if (rs) {
 998→            rs.sessionSettings = {
 999→              scale: String(msg.scale || rs.sessionSettings.scale),
1000→              bpm: Number(msg.bpm) || rs.sessionSettings.bpm,
1001→              timeSignature: String(msg.timeSignature || rs.sessionSettings.timeSignature),
1002→            };
1003→            broadcastToRoom(rs, JSON.stringify({ type: "session_settings", ...rs.sessionSettings }));
1004→          }
1005→        } else if (msgType === "hand_state") {
1006→          const rs = roomSession as RoomSession | null;
1007→          if (rs) {
1008→            rs.bothHandsDetected = Boolean(msg.bothHands);
1009→            broadcastToRoom(rs, JSON.stringify({ type: "hand_state", hands: msg.hands, bothHands: msg.bothHands }));
1010→          }
1011→        } else if (msgType === "refresh_camera") {
1012→          // Broadcast to secondary devices to restart camera
1013→          if (roomSession) broadcastToRoom(roomSession, JSON.stringify({ type: "refresh_camera" }));
1014→        } else if (msgType === "set_device_role") {
1015→          const { deviceId, role, enabled } = msg;
1016→          if (roomSession && (role === "mic" || role === "midi" || role === "camera")) {
1017→            setDeviceRole(roomSession as RoomSession, deviceId, role, Boolean(enabled));
1018→            console.log(`[${APP_NAME}] Role ${role}=${enabled} on device ${deviceId}`);
1019→          }
1020→        } else if (msgType === "close") {
1021→          break;
1022→        }
1023→      }
1024→    }
1025→  } catch (e: any) {
1026→    if (!closed) console.log(`[${APP_NAME}] receive error:`, e?.message);
1027→  }
1028→
1029→  closed = true;
1030→  clearInterval(primaryPingInterval);
1031→  try { session.close(); } catch {}
1032→
1033→  // Cleanup
1034→  const rs = rooms.get(roomCode);
1035→  if (rs?.midiFlushTimer) clearTimeout(rs.midiFlushTimer);
1036→  if (rs) {
1037→    for (const d of rs.devices.values()) {
1038→      if (!d.isPrimary && d.ws.readyState === WebSocket.OPEN) {
1039→        try {
1040→          d.ws.send(JSON.stringify({ type: "room_closed" }));
1041→          d.ws.close();
1042→        } catch {}
1043→      }
1044→    }
1045→  }
1046→  rooms.delete(roomCode);
1047→  console.log(`[${APP_NAME}] Primary disconnected: ${sessionId}, room ${roomCode} removed`);
1048→  try { ws.close(); } catch {}
1049→}
