 897→  function midiToVexflow(midi, key, explicitAcc, measureIdx, clefForShift, noteBeat) {
 898→    var pc = midi % 12;
 899→
 900→    // Check enharmonic overrides from text data
 901→    if (currentTextData && currentTextData.enharmonicOverrides && typeof measureIdx === 'number') {
 902→      var overrides = currentTextData.enharmonicOverrides;
 903→      for (var oi = 0; oi < overrides.length; oi++) {
 904→        var ov = overrides[oi];
 905→        var range = ov.measureRange;
 906→        if (measureIdx >= range[0] && measureIdx <= range[1]) {
 907→          // Check if this section uses flats (key change to Db major etc.)
 908→          if (ov.useFlats) {
 909→            // Use flat spelling for this section — but respect key signature
 910→            var octF = Math.floor(midi / 12) - 1;
 911→            var nameF = NOTE_NAMES_FLAT[pc];
 912→            var accF = NOTE_ACCS_FLAT[pc];
 913→            var vfKeyF = nameF + (accF || '') + '/' + octF;
 914→            // Determine visible accidental using key signature
 915→            var visAccF = null;
 916→            var vfKeyLookup = keyToVexflow(key);
 917→            var kFlats = KEY_SIG_FLATS[vfKeyLookup] || [];
 918→            if (accF === 'b') {
 919→              // Only show flat if NOT already in key signature
 920→              var inKeySig = false;
 921→              for (var kfi = 0; kfi < kFlats.length; kfi++) {
 922→                if (kFlats[kfi] === pc) { inKeySig = true; break; }
 923→              }
 924→              if (!inKeySig) visAccF = 'b';
 925→            } else if (accF === 'bb') {
 926→              visAccF = 'bb'; // double-flat always shown
 927→            } else {
 928→              // Natural note: show natural if key sig has a flat on this letter
 929→              var flatNatPCs = { 10:11, 3:4, 8:9, 1:2, 6:7, 11:0, 4:5 };
 930→              for (var fni = 0; fni < kFlats.length; fni++) {
 931→                if (pc === flatNatPCs[kFlats[fni]]) { visAccF = 'n'; break; }
 932→              }
 933→            }
 934→            return { key: vfKeyF, accidental: visAccF };
 935→          }
 936→          // Check enharmonic rules for this section
 937→          if (ov.rules) {
 938→            for (var ri = 0; ri < ov.rules.length; ri++) {
 939→              var rule = ov.rules[ri];
 940→              if (pc === rule.midiPC) {
 941→                // Skip override if note has explicit natural — means it's genuinely a natural, not an enharmonic
 942→                if (explicitAcc === 'n') {
 943→                  break; // use default rendering with natural sign
 944→                }
 945→                // Compute octave for the display note
 946→                var basePC = LETTER_PC[rule.displayNote];
 947→                var accOff = ACC_OFFSET[rule.displayAcc] || 0;
 948→                var dispOct = Math.floor((midi - basePC - accOff) / 12) - 1;
 949→                // Correct for notes crossing octave boundary (e.g., B#4 = C5)
 950→                if ((dispOct + 1) * 12 + basePC + accOff !== midi) {
 951→                  dispOct = Math.round((midi - basePC - accOff) / 12) - 1;
 952→                }
 953→                var vfKeyR = rule.displayNote + '/' + dispOct;
 954→                return { key: vfKeyR, accidental: rule.displayAcc };
 955→              }
 956→            }
