1724→  // Break a duration gap into standard rest durations
1725→  function fitRests(gap) {
1726→    var rests = [];
1727→    var sizes = [2.0, 1.0, 0.5, 0.25, 0.125];
1728→    var remaining = gap;
1729→    for (var s = 0; s < sizes.length && remaining > 0.01; s++) {
1730→      while (remaining >= sizes[s] - 0.01) {
1731→        rests.push(sizes[s]);
1732→        remaining -= sizes[s];
1733→      }
1734→    }
1735→    return rests;
1736→  }
