}

// ─── VexFlow Rendering ───────────────────────────────────────

var VF = Vex.Flow;

var NOTE_NAMES_SHARP = ['c','c','d','d','e','f','f','g','g','a','a','b'];
var NOTE_ACCS_SHARP  = ['','#','','#','','','#','','#','','#',''];
var NOTE_NAMES_FLAT  = ['c','d','d','e','e','f','g','g','a','a','b','b'];
var NOTE_ACCS_FLAT   = ['','b','','b','','','b','','b','','b',''];

var FLAT_KEYS = ['F major','Bb major','Eb major','Ab major','Db major','Gb major',
  'D minor','G minor','C minor','F minor','Bb minor','Eb minor'];

function isFlat(key) { return FLAT_KEYS.indexOf(key) >= 0; }

// Look up the active key for a given measure index, using keyChanges from text data
function getActiveKey(measureIdx, defaultKey) {
  if (!currentTextData || !currentTextData.keyChanges) return defaultKey;
  var kc = currentTextData.keyChanges;
  var activeKey = defaultKey;
  for (var ki = 0; ki < kc.length; ki++) {
    if (measureIdx >= kc[ki].measure) activeKey = kc[ki].key;
  }
  return activeKey;
}

// Key signature sharp/flat pitch classes
// Sharp keys: F#=6, C#=1, G#=8, D#=3, A#=10, E#=5, B#=0 (order of sharps)
// Flat keys: Bb=10, Eb=3, Ab=8, Db=1, Gb=6, Cb=11, Fb=4 (order of flats)
var KEY_SIG_SHARPS = {
  'A': [6,1,8], 'E': [6,1,8,3], 'B': [6,1,8,3,10], 'F#': [6,1,8,3,10,5],
  'D': [6,1], 'G': [6],
  'Am': [], 'Em': [6], 'Bm': [6,1], 'F#m': [6,1,8], 'C#m': [6,1,8,3],
  'G#m': [6,1,8,3,10], 'D#m': [6,1,8,3,10,5]
};
var KEY_SIG_FLATS = {
  'F': [10], 'Bb': [10,3], 'Eb': [10,3,8], 'Ab': [10,3,8,1],
  'Db': [10,3,8,1,6], 'Gb': [10,3,8,1,6,11], 'Cb': [10,3,8,1,6,11,4],
  'Dm': [10], 'Gm': [10,3], 'Cm': [10,3,8], 'Fm': [10,3,8,1],
  'Bbm': [10,3,8,1,6], 'Ebm': [10,3,8,1,6,11]
};

// Letter name base MIDI pitch classes: c=0, d=2, e=4, f=5, g=7, a=9, b=11
var LETTER_PC = { c:0, d:2, e:4, f:5, g:7, a:9, b:11 };
var ACC_OFFSET = { '':0, '#':1, '##':2, 'b':-1, 'bb':-2, 'n':0 };

function midiToVexflow(midi, key, explicitAcc, measureIdx, clefForShift, noteBeat) {
  var pc = midi % 12;

  // Check enharmonic overrides from text data
  if (currentTextData && currentTextData.enharmonicOverrides && typeof measureIdx === 'number') {
    var overrides = currentTextData.enharmonicOverrides;
    for (var oi = 0; oi < overrides.length; oi++) {
      var ov = overrides[oi];
      var range = ov.measureRange;
      if (measureIdx >= range[0] && measureIdx <= range[1]) {
        // Check if this section uses flats (key change to Db major etc.)
        if (ov.useFlats) {
          // Use flat spelling for this section — but respect key signature
          var octF = Math.floor(midi / 12) - 1;
          var nameF = NOTE_NAMES_FLAT[pc];
          var accF = NOTE_ACCS_FLAT[pc];
          var vfKeyF = nameF + (accF || '') + '/' + octF;
          // Determine visible accidental using key signature
          var visAccF = null;
          var vfKeyLookup = keyToVexflow(key);
          var kFlats = KEY_SIG_FLATS[vfKeyLookup] || [];
          if (accF === 'b') {
            // Only show flat if NOT already in key signature
            var inKeySig = false;
            for (var kfi = 0; kfi < kFlats.length; kfi++) {
              if (kFlats[kfi] === pc) { inKeySig = true; break; }
            }
            if (!inKeySig) visAccF = 'b';
          } else if (accF === 'bb') {
            visAccF = 'bb'; // double-flat always shown
          } else {
            // Natural note: show natural if key sig has a flat on this letter
            var flatNatPCs = { 10:11, 3:4, 8:9, 1:2, 6:7, 11:0, 4:5 };
            for (var fni = 0; fni < kFlats.length; fni++) {
              if (pc === flatNatPCs[kFlats[fni]]) { visAccF = 'n'; break; }
            }
          }
          return { key: vfKeyF, accidental: visAccF };
        }
        // Check enharmonic rules for this section
        if (ov.rules) {
          for (var ri = 0; ri < ov.rules.length; ri++) {
            var rule = ov.rules[ri];
            if (pc === rule.midiPC) {
              // Skip override if note has explicit natural — means it's genuinely a natural, not an enharmonic
              if (explicitAcc === 'n') {
                break; // use default rendering with natural sign
              }
              // Compute octave for the display note
              var basePC = LETTER_PC[rule.displayNote];
              var accOff = ACC_OFFSET[rule.displayAcc] || 0;
              var dispOct = Math.floor((midi - basePC - accOff) / 12) - 1;
              // Correct for notes crossing octave boundary (e.g., B#4 = C5)
              if ((dispOct + 1) * 12 + basePC + accOff !== midi) {
                dispOct = Math.round((midi - basePC - accOff) / 12) - 1;
              }
              var vfKeyR = rule.displayNote + '/' + dispOct;
              return { key: vfKeyR, accidental: rule.displayAcc };
            }
          }
        }
        break; // found the matching range, use default logic
      }
    }
  }

  // Check 8va display shift — show treble notes one octave lower on staff
  var displayMidi = midi;
  if (clefForShift === 'treble' && currentTextData && currentTextData.octaveShifts && typeof measureIdx === 'number') {
    var shifts = currentTextData.octaveShifts;
    for (var si = 0; si < shifts.length; si++) {
      var srange = shifts[si].measureRange;
      var midiMin = shifts[si].midiMin || 0;
      var startBeat = shifts[si].startBeat || 0;
      if (srange && measureIdx >= srange[0] && measureIdx <= srange[1] && midi >= midiMin && (typeof noteBeat !== 'number' || noteBeat >= startBeat)) {
        displayMidi = midi - 12; // display one octave lower
        break;
      }
    }
  }

  var octave = Math.floor(displayMidi / 12) - 1;
  pc = displayMidi % 12;
  var flat = isFlat(key);
  var name = flat ? NOTE_NAMES_FLAT[pc] : NOTE_NAMES_SHARP[pc];
  var acc = flat ? NOTE_ACCS_FLAT[pc] : NOTE_ACCS_SHARP[pc];
  // VexFlow key string needs accidental for correct pitch positioning
  var vfKey = name + (acc ? acc : '') + '/' + octave;

  // Determine visible accidental
  var visibleAcc = explicitAcc || null;
  if (!visibleAcc) {
    var vfKey2 = keyToVexflow(key);
    var keySharps = KEY_SIG_SHARPS[vfKey2] || [];
    var keyFlats = KEY_SIG_FLATS[vfKey2] || [];
    // Natural needed: note is unaltered but key sig has a sharp/flat on this letter
    // e.g. C natural in C# minor (C# in key sig) → show natural
    if (keySharps.length > 0) {
      var sharpLetterPCs = { 6:5, 1:0, 8:7, 3:2, 10:9, 5:4, 0:11 }; // sharp_pc → natural_pc
      for (var si2 = 0; si2 < keySharps.length; si2++) {
        if (pc === sharpLetterPCs[keySharps[si2]]) {
          visibleAcc = 'n';
          break;
        }
      }
    }
    if (keyFlats.length > 0 && !visibleAcc) {
      var flatLetterPCs = { 10:11, 3:4, 8:9, 1:2, 6:7, 11:0, 4:5 }; // flat_pc → natural_pc
      for (var fi = 0; fi < keyFlats.length; fi++) {
        if (pc === flatLetterPCs[keyFlats[fi]]) {
          visibleAcc = 'n';
          break;
        }
      }
    }
  }
  return { key: vfKey, accidental: visibleAcc };
}

function durToVexflow(dur) {
  // Sextuplet notes (dur ~0.33) are eighth notes played 6-in-the-space-of-4
  // Map them to '8' so VF.Tuplet can handle the timing
  if (Math.abs(dur - 0.33) < 0.05 || Math.abs(dur - 1/3) < 0.01) return '8';
  var map = [
    [4.0, 'w'], [3.0, 'hd'], [2.0, 'h'], [1.5, 'qd'], [1.0, 'q'],
    [0.75, '8d'], [0.5, '8'], [0.375, '16d'], [0.25, '16'], [0.125, '32']
  ];
  var best = 'q';
  var bestDiff = Infinity;
  for (var i = 0; i < map.length; i++) {
    var diff = Math.abs(dur - map[i][0]);
    if (diff < bestDiff) { bestDiff = diff; best = map[i][1]; }
  }
  return best;
}

function keyToVexflow(key) {
  if (!key) return 'C';
  var map = {
    'C major': 'C', 'G major': 'G', 'D major': 'D', 'A major': 'A', 'E major': 'E', 'B major': 'B',
    'F# major': 'F#', 'Gb major': 'Gb', 'F major': 'F', 'Bb major': 'Bb', 'Eb major': 'Eb',
    'Ab major': 'Ab', 'Db major': 'Db', 'Cb major': 'Cb',
    'A minor': 'Am', 'E minor': 'Em', 'B minor': 'Bm', 'F# minor': 'F#m',
    'C# minor': 'C#m', 'D minor': 'Dm', 'G minor': 'Gm', 'C minor': 'Cm',
    'F minor': 'Fm', 'Bb minor': 'Bbm', 'Eb minor': 'Ebm'
  };
  return map[key] || 'C';
}

function renderVexFlow() {
  renderVexFlowInto($('#vexflow-side'));
}

