// Simple voice builder (no rests) — for pickup measures
function buildVoiceNotes(notes, key, clef, measureIdx) {
  notes = notes.slice().sort(function(a, b) { return a.beat - b.beat; });
  var groups = [];
  var lastBeat = -1;
  for (var i = 0; i < notes.length; i++) {
    if (groups.length > 0 && Math.abs(notes[i].beat - lastBeat) < 0.01) {
      groups[groups.length - 1].push(notes[i]);
    } else {
      groups.push([notes[i]]);
      lastBeat = notes[i].beat;
    }
