  var vfNotes = [];
  // Pre-scan: detect noteIds with mixed accidentals (e.g. D# and D♮ on same letter)
  // so we can show courtesy key-sig accidentals on the first occurrence
  var noteAccSets = {};
  for (var pi = 0; pi < notes.length; pi++) {
    var pResult = midiToVexflow(notes[pi].midi, key, notes[pi].acc, measureIdx, clef, notes[pi].beat);
    var pId = pResult.key.replace(/(?<=^[a-g])(#|b)+(?=\/)/, '');
    var pAcc = pResult.accidental;
    if (!noteAccSets[pId]) noteAccSets[pId] = {};
    noteAccSets[pId][pAcc === null ? '__null__' : pAcc] = true;
  }
  var mixedAccIds = {};
  for (var mid in noteAccSets) {
    if (Object.keys(noteAccSets[mid]).length > 1) mixedAccIds[mid] = true;
  }
  var shownAccidentals = {}; // track "noteName/octave" → accidental already shown in this measure
  for (var g = 0; g < groups.length; g++) {
    var group = groups[g];
    var dur = durToVexflow(group[0].dur);
    var keys = [];
    var accs = [];
    for (var n = 0; n < group.length; n++) {
      var result = midiToVexflow(group[n].midi, key, group[n].acc, measureIdx, clef, group[n].beat);
      keys.push(result.key);
      var acc = result.accidental;
      // noteId = letter/octave only (strip accidentals) so C##/5 and C#/5 map to same tracker slot
      var noteId = result.key.replace(/(?<=^[a-g])(#|b)+(?=\/)/, '');
      // Courtesy: show key-sig accidental when same letter has mixed accidentals in this measure
      if (!acc && mixedAccIds[noteId]) {
        var courtesyPC = group[n].midi % 12;
        var vfKeyC = keyToVexflow(key);
        var ksharpsC = KEY_SIG_SHARPS[vfKeyC] || [];
        for (var kci = 0; kci < ksharpsC.length; kci++) {
          if (ksharpsC[kci] === courtesyPC) { acc = '#'; break; }
        }
        if (!acc) {
          var kflatsC = KEY_SIG_FLATS[vfKeyC] || [];
          for (var kcj = 0; kcj < kflatsC.length; kcj++) {
            if (kflatsC[kcj] === courtesyPC) { acc = 'b'; break; }
          }
        }
      }
      var cancelAcc = null; // prepended cancellation accidental (e.g., ♮ before # when canceling ##)
      if (acc) {
        if (shownAccidentals[noteId] === acc) {
          acc = null; // same accidental already shown on this note in this measure
        } else {
          var prev = shownAccidentals[noteId];
          // Compound accidental: ## → # needs ♮# ; bb → b needs ♮b
          if (prev === '##' && (acc === '#' || acc === 'n')) {
            cancelAcc = 'n';
          } else if (prev === 'bb' && (acc === 'b' || acc === 'n')) {
            cancelAcc = 'n';
          }
          shownAccidentals[noteId] = acc;
        }
      } else if (noteId in shownAccidentals && shownAccidentals[noteId] !== null) {
        var prev2 = shownAccidentals[noteId];
        var notePC2 = group[n].midi % 12;
        var vfKeyL = keyToVexflow(key);
        var ksharps2 = KEY_SIG_SHARPS[vfKeyL] || [];
        var kflats2 = KEY_SIG_FLATS[vfKeyL] || [];
        var inKeyAcc = null;
        for (var ki2 = 0; ki2 < ksharps2.length; ki2++) { if (ksharps2[ki2] === notePC2) { inKeyAcc = '#'; break; } }
        if (!inKeyAcc) { for (var ki3 = 0; ki3 < kflats2.length; ki3++) { if (kflats2[ki3] === notePC2) { inKeyAcc = 'b'; break; } } }
        if (prev2 === '##' || prev2 === 'bb') {
          cancelAcc = 'n';
        }
        acc = inKeyAcc || 'n';
        shownAccidentals[noteId] = acc === 'n' ? null : acc;
