// Break a duration gap into standard rest durations
function fitRests(gap) {
  var rests = [];
  var sizes = [2.0, 1.0, 0.5, 0.25, 0.125];
  var remaining = gap;
  for (var s = 0; s < sizes.length && remaining > 0.01; s++) {
    while (remaining >= sizes[s] - 0.01) {
      rests.push(sizes[s]);
      remaining -= sizes[s];
    }
  }
  return rests;
}

