pbBpm.addEventListener('change', function() {
  playbackState.bpm = parseInt(pbBpm.value) || 120;
});

function startPlayback() {
  if (!currentJson || measurePositionMap.length === 0) return;
  Tone.start(); // unlock audio context on user gesture

  var data = currentJson;
  var bpm = data.tempo || parseInt(pbBpm.value) || 120;
  playbackState.bpm = bpm;
  pbBpm.value = bpm;
  Tone.Transport.bpm.value = bpm;

  if (playbackState.playing) return;

  // Create synth if needed
  if (!playbackState.synth) {
    playbackState.synth = new Tone.PolySynth(Tone.Synth, {
      maxPolyphony: 32,
      voice: Tone.Synth,
      options: {
        oscillator: { type: 'triangle8' },
        envelope: { attack: 0.005, decay: 0.3, sustain: 0.4, release: 0.8 }
      }
    }).toDestination();
    playbackState.synth.volume.value = -6;
  }

  // Calculate total beats
  var lastMap = measurePositionMap[measurePositionMap.length - 1];
  playbackState.totalBeats = lastMap.startBeat + lastMap.beatsPerMeasure;

  // Schedule all notes
  var secondsPerBeat = 60 / bpm;
  playbackState.scheduledIds = [];

  for (var mi = 0; mi < data.measures.length; mi++) {
    var m = data.measures[mi];
    if (!m || !m.notes) continue;
    // Find this measure in position map
    var posEntry = null;
    for (var pi = 0; pi < measurePositionMap.length; pi++) {
      if (measurePositionMap[pi].measureIdx === mi) { posEntry = measurePositionMap[pi]; break; }
    }
    if (!posEntry) continue;

    for (var ni = 0; ni < m.notes.length; ni++) {
      var note = m.notes[ni];
      var absTime = (posEntry.startBeat + note.beat) * secondsPerBeat;
      var durSec = note.dur * secondsPerBeat;
      var freq = Tone.Frequency(note.midi, 'midi').toFrequency();
      var vel = note.vel != null ? Math.max(0.05, note.vel / 127) : 0.7;

      var id = Tone.Transport.schedule(
        (function(f, d, v) { return function(time) {
          if (playbackState.synth) {
            playbackState.synth.triggerAttackRelease(f, d, time, v);
          }
        }; })(freq, Math.min(durSec, 4), vel),
        absTime
      );
      playbackState.scheduledIds.push(id);
    }
  }

  // Resume from pause position or start
  if (playbackState.pauseTime > 0) {
    Tone.Transport.start('+0', playbackState.pauseTime);
  } else {
    Tone.Transport.start('+0', 0);
  }

  playbackState.playing = true;
  playbackState.startTime = Tone.now() - (playbackState.pauseTime || 0);
  pbPlay.style.display = 'none';
  pbPause.style.display = 'inline-flex';
  pbStop.disabled = false;

  // Start cursor animation
  animateCursor();

  // Auto-stop at end
  var totalDuration = playbackState.totalBeats * secondsPerBeat;
  Tone.Transport.schedule(function() {
    stopPlayback();
  }, totalDuration + 0.1);
}

function pausePlayback() {
  if (!playbackState.playing) return;
  playbackState.pauseTime = Tone.Transport.seconds;
  Tone.Transport.pause();
  playbackState.playing = false;
  pbPlay.style.display = 'inline-flex';
  pbPause.style.display = 'none';
  if (playbackState.animFrame) cancelAnimationFrame(playbackState.animFrame);
}

function stopPlayback() {
  Tone.Transport.stop();
  Tone.Transport.cancel(); // clear all scheduled events
  playbackState.playing = false;
  playbackState.pauseTime = 0;
  playbackState.scheduledIds = [];
  pbPlay.style.display = 'inline-flex';
  pbPause.style.display = 'none';
  pbStop.disabled = true;
  if (playbackState.animFrame) cancelAnimationFrame(playbackState.animFrame);
  removeCursor();
  updateTimeDisplay(0);
}

function animateCursor() {
  if (!playbackState.playing) return;

  var elapsed = Tone.Transport.seconds;
  var secondsPerBeat = 60 / playbackState.bpm;
  var currentBeat = elapsed / secondsPerBeat;

  updateTimeDisplay(elapsed);
  updateCursorPosition(currentBeat);

  if (currentBeat < playbackState.totalBeats) {
    playbackState.animFrame = requestAnimationFrame(animateCursor);
  } else {
    stopPlayback();
  }
}

function updateTimeDisplay(elapsed) {
  var secondsPerBeat = 60 / playbackState.bpm;
  var totalSec = playbackState.totalBeats * secondsPerBeat;
  var curMin = Math.floor(elapsed / 60);
  var curSec = Math.floor(elapsed % 60);
  var totMin = Math.floor(totalSec / 60);
  var totSec = Math.floor(totalSec % 60);
  pbTime.textContent = curMin + ':' + (curSec < 10 ? '0' : '') + curSec + ' / ' + totMin + ':' + (totSec < 10 ? '0' : '') + totSec;
}

function updateCursorPosition(currentBeat) {
  // Find which measure we're in
  var entry = null;
  for (var i = measurePositionMap.length - 1; i >= 0; i--) {
    if (currentBeat >= measurePositionMap[i].startBeat - 0.01) {
      entry = measurePositionMap[i];
      break;
    }
  }
  if (!entry) return;

  // Interpolate X within the measure
  var beatInMeasure = currentBeat - entry.startBeat;
  var fraction = Math.min(1, beatInMeasure / entry.beatsPerMeasure);
  var cursorX = entry.x + fraction * entry.width;
  var cursorY = entry.y;

  // Get or create cursor line in the SVG
  var svgContainer = document.getElementById('vexflow-side');
  if (!svgContainer) return;
  var svg = svgContainer.querySelector('svg');
  if (!svg) return;

  var ns = 'http://www.w3.org/2000/svg';
  var cursor = svg.querySelector('#playback-cursor');
  if (!cursor) {
    cursor = document.createElementNS(ns, 'line');
    cursor.setAttribute('id', 'playback-cursor');
    cursor.setAttribute('stroke', '#ef4444');
    cursor.setAttribute('stroke-width', '2');
    cursor.setAttribute('stroke-opacity', '0.8');
    svg.appendChild(cursor);
  }

  cursor.setAttribute('x1', Math.round(cursorX));
  cursor.setAttribute('x2', Math.round(cursorX));
  cursor.setAttribute('y1', Math.round(cursorY - 5));
  cursor.setAttribute('y2', Math.round(cursorY + 210)); // span both treble + bass staves

  // Auto-scroll to keep cursor visible
  var scrollContainer = svgContainer.closest('.pane') || svgContainer;
  if (scrollContainer && scrollContainer.scrollHeight > scrollContainer.clientHeight) {
    var cursorScreenY = cursorY - scrollContainer.scrollTop;
    if (cursorScreenY > scrollContainer.clientHeight - 100 || cursorScreenY < 50) {
      scrollContainer.scrollTop = cursorY - 100;
    }
  }
}

function removeCursor() {
  var svgContainer = document.getElementById('vexflow-side');
  if (!svgContainer) return;
  var svg = svgContainer.querySelector('svg');
  if (!svg) return;
  var cursor = svg.querySelector('#playback-cursor');
  if (cursor) cursor.remove();
}

// Update BPM display when a new file loads
function updatePlaybackBpm() {
  if (currentJson && currentJson.tempo) {
    pbBpm.value = currentJson.tempo;
    playbackState.bpm = currentJson.tempo;
  }
}

// ─── Terminal Panel ─────────────────────────────────────────

var termPanel = document.getElementById('terminal-panel');
var termContainer = document.getElementById('terminal-container');

