async function loadLibrary() {
  try {
    var r = await fetch('/api/library');
    var data = await r.json();
    renderTree(data, treeEl);
  } catch (e) { showToast('Failed to load library: ' + e.message); }
}

function renderTree(items, container) {
  while (container.firstChild) container.removeChild(container.firstChild);
  for (var i = 0; i < items.length; i++) {
    var item = items[i];
    if (item.type === 'directory') {
      var dir = document.createElement('div');
      dir.className = 'tree-dir';
      var label = document.createElement('div');
      label.className = 'tree-dir-label';
      var arrow = document.createElement('span');
      arrow.className = 'arrow';
      arrow.textContent = '\u25BC';
      label.appendChild(arrow);
      var nameSpan = document.createElement('span');
      nameSpan.textContent = ' ' + item.name;
      label.appendChild(nameSpan);
      label.addEventListener('click', (function(d) { return function() { d.classList.toggle('collapsed'); }; })(dir));
      dir.appendChild(label);
      var children = document.createElement('div');
      children.className = 'tree-children';
      if (item.children) renderTree(item.children, children);
      dir.appendChild(children);
      container.appendChild(dir);
    } else {
      var file = document.createElement('div');
      file.className = 'tree-file';
      file.setAttribute('data-path', item.path);
      file.setAttribute('data-has-claude', String(!!item.hasClaude));
      file.setAttribute('data-has-gemini', String(!!item.hasGemini));
      var dots = document.createElement('span');
      dots.className = 'status-dots';
      var dotC = document.createElement('span');
      dotC.className = 'status-dot ' + (item.hasClaude ? 'claude' : 'pending');
      dotC.title = item.hasClaude ? 'Claude: converted' : 'Claude: pending';
      var dotG = document.createElement('span');
      dotG.className = 'status-dot ' + (item.hasGemini ? 'gemini' : 'pending');
      dotG.title = item.hasGemini ? 'Gemini: converted' : 'Gemini: pending';
      dots.appendChild(dotC);
      dots.appendChild(dotG);
      file.appendChild(dots);
      var fname = document.createElement('span');
      fname.className = 'fname';
      fname.textContent = item.name;
      file.appendChild(fname);
      file.addEventListener('click', (function(p, hc, hg) {
        return function() {
          var hasJson = currentModel === 'claude' ? hc : hg;
          selectFile(p, hasJson, hc, hg);
        };
      })(item.path, item.hasClaude, item.hasGemini));
      container.appendChild(file);
    }
  }
}

async function selectFile(filePath, hasJson, hasClaude, hasGemini) {
  currentFile = filePath;
  currentJson = null;
  document.querySelectorAll('.tree-file').forEach(function(f) { f.classList.remove('active'); });
  var active = document.querySelector('.tree-file[data-path="' + CSS.escape(filePath) + '"]');
  if (active) active.classList.add('active');
  headerInfo.textContent = filePath + ' [' + currentModel + ']';

  if (hasJson) {
    var jsonPath = filePath.replace(/\.[^.]+$/, '.json');
    var layoutPath = filePath.replace(/\.[^.]+$/, '.layout.json');
    var textPath = filePath.replace(/\.[^.]+$/, '.text.json');
    try {
      var r = await fetch('/output/' + currentModel + '/' + jsonPath);
      currentJson = await r.json();
      // Load layout and text data (optional, don't fail if missing)
      try { var lr = await fetch('/output/' + currentModel + '/' + layoutPath); currentLayout = await lr.json(); } catch(e2) { currentLayout = null; }
      try { var tr = await fetch('/output/' + currentModel + '/' + textPath); currentTextData = await tr.json(); } catch(e3) { currentTextData = null; }
      showCompareView();
      return;
    } catch(e) { /* fall through to detail view */ }
  }
  showDetailView();
}

