// ============================================================================
// SMR Score Browser — VexFlow + Tone.js + pdf.js (ported from SheetMusicReader)
// ============================================================================

var smrCurrentJson = null;
var smrCurrentLayout = null;
var smrCurrentTextData = null;
var smrCurrentFile = null;
var smrViewMode = 'svg'; // 'svg' | 'pdf'
var smrMeasurePositionMap = [];
var smrPlaybackState = { playing: false, startTime: 0, pauseTime: 0, totalBeats: 0, bpm: 120, synth: null, scheduledIds: [], animFrame: null };

// ── VexFlow lookup tables ──
var VF = typeof Vex !== 'undefined' ? Vex.Flow : null;
var SMR_NOTE_NAMES_SHARP = ['c','c','d','d','e','f','f','g','g','a','a','b'];
var SMR_NOTE_ACCS_SHARP  = ['','#','','#','','','#','','#','','#',''];
var SMR_NOTE_NAMES_FLAT  = ['c','d','d','e','e','f','g','g','a','a','b','b'];
var SMR_NOTE_ACCS_FLAT   = ['','b','','b','','','b','','b','','b',''];
var SMR_FLAT_KEYS = ['F major','Bb major','Eb major','Ab major','Db major','Gb major',
  'D minor','G minor','C minor','F minor','Bb minor','Eb minor'];
function smrIsFlat(key) { return SMR_FLAT_KEYS.indexOf(key) >= 0; }

var SMR_KEY_SIG_SHARPS = {
  'A': [6,1,8], 'E': [6,1,8,3], 'B': [6,1,8,3,10], 'F#': [6,1,8,3,10,5],
  'D': [6,1], 'G': [6],
  'Am': [], 'Em': [6], 'Bm': [6,1], 'F#m': [6,1,8], 'C#m': [6,1,8,3],
  'G#m': [6,1,8,3,10], 'D#m': [6,1,8,3,10,5]
};
var SMR_KEY_SIG_FLATS = {
  'F': [10], 'Bb': [10,3], 'Eb': [10,3,8], 'Ab': [10,3,8,1],
  'Db': [10,3,8,1,6], 'Gb': [10,3,8,1,6,11], 'Cb': [10,3,8,1,6,11,4],
  'Dm': [10], 'Gm': [10,3], 'Cm': [10,3,8], 'Fm': [10,3,8,1],
  'Bbm': [10,3,8,1,6], 'Ebm': [10,3,8,1,6,11]
};
var SMR_LETTER_PC = { c:0, d:2, e:4, f:5, g:7, a:9, b:11 };
var SMR_ACC_OFFSET = { '':0, '#':1, '##':2, 'b':-1, 'bb':-2, 'n':0 };

// ── VexFlow helpers ──
function smrGetActiveKey(measureIdx, defaultKey) {
  if (!smrCurrentTextData || !smrCurrentTextData.keyChanges) return defaultKey;
  var kc = smrCurrentTextData.keyChanges;
  var activeKey = defaultKey;
  for (var ki = 0; ki < kc.length; ki++) {
    if (measureIdx >= kc[ki].measure) activeKey = kc[ki].key;
  }
  return activeKey;
}

function smrKeyToVexflow(key) {
  if (!key) return 'C';
  var map = {
    'C major': 'C', 'G major': 'G', 'D major': 'D', 'A major': 'A', 'E major': 'E', 'B major': 'B',
    'F# major': 'F#', 'Gb major': 'Gb', 'F major': 'F', 'Bb major': 'Bb', 'Eb major': 'Eb',
    'Ab major': 'Ab', 'Db major': 'Db', 'Cb major': 'Cb',
    'A minor': 'Am', 'E minor': 'Em', 'B minor': 'Bm', 'F# minor': 'F#m',
    'C# minor': 'C#m', 'D minor': 'Dm', 'G minor': 'Gm', 'C minor': 'Cm',
    'F minor': 'Fm', 'Bb minor': 'Bbm', 'Eb minor': 'Ebm'
  };
  return map[key] || 'C';
}

function smrDurToVexflow(dur) {
  if (Math.abs(dur - 0.33) < 0.05 || Math.abs(dur - 1/3) < 0.01) return '8';
  var map = [
    [4.0, 'w'], [3.0, 'hd'], [2.0, 'h'], [1.5, 'qd'], [1.0, 'q'],
    [0.75, '8d'], [0.5, '8'], [0.375, '16d'], [0.25, '16'], [0.125, '32']
  ];
  var best = 'q';
  var bestDiff = Infinity;
  for (var i = 0; i < map.length; i++) {
    var diff = Math.abs(dur - map[i][0]);
    if (diff < bestDiff) { bestDiff = diff; best = map[i][1]; }
  }
  return best;
}

function smrFitRests(gap) {
  var rests = [];
  var sizes = [2.0, 1.0, 0.5, 0.25, 0.125];
  var remaining = gap;
  for (var s = 0; s < sizes.length && remaining > 0.01; s++) {
    while (remaining >= sizes[s] - 0.01) {
      rests.push(sizes[s]);
      remaining -= sizes[s];
    }
  }
  return rests;
}

function smrMidiToVexflow(midi, key, explicitAcc, measureIdx, clefForShift, noteBeat) {
  var pc = midi % 12;
  // Enharmonic overrides
  if (smrCurrentTextData && smrCurrentTextData.enharmonicOverrides && typeof measureIdx === 'number') {
    var overrides = smrCurrentTextData.enharmonicOverrides;
    for (var oi = 0; oi < overrides.length; oi++) {
      var ov = overrides[oi];
      var range = ov.measureRange;
      if (measureIdx >= range[0] && measureIdx <= range[1]) {
        if (ov.useFlats) {
          var octF = Math.floor(midi / 12) - 1;
          var nameF = SMR_NOTE_NAMES_FLAT[pc];
          var accF = SMR_NOTE_ACCS_FLAT[pc];
          var vfKeyF = nameF + (accF || '') + '/' + octF;
          var visAccF = null;
          var vfKeyLookup = smrKeyToVexflow(key);
          var kFlats = SMR_KEY_SIG_FLATS[vfKeyLookup] || [];
          if (accF === 'b') {
            var inKeySig = false;
            for (var kfi = 0; kfi < kFlats.length; kfi++) {
              if (kFlats[kfi] === pc) { inKeySig = true; break; }
            }
            if (!inKeySig) visAccF = 'b';
          } else if (accF === 'bb') {
            visAccF = 'bb';
          } else {
            var flatNatPCs = { 10:11, 3:4, 8:9, 1:2, 6:7, 11:0, 4:5 };
            for (var fni = 0; fni < kFlats.length; fni++) {
              if (pc === flatNatPCs[kFlats[fni]]) { visAccF = 'n'; break; }
            }
          }
          return { key: vfKeyF, accidental: visAccF };
        }
        if (ov.rules) {
          for (var ri = 0; ri < ov.rules.length; ri++) {
            var rule = ov.rules[ri];
            if (pc === rule.midiPC) {
              if (explicitAcc === 'n') break;
              var basePC = SMR_LETTER_PC[rule.displayNote];
              var accOff = SMR_ACC_OFFSET[rule.displayAcc] || 0;
              var dispOct = Math.floor((midi - basePC - accOff) / 12) - 1;
              if ((dispOct + 1) * 12 + basePC + accOff !== midi) {
                dispOct = Math.round((midi - basePC - accOff) / 12) - 1;
              }
              return { key: rule.displayNote + '/' + dispOct, accidental: rule.displayAcc };
            }
          }
        }
        break;
      }
    }
  }
  // 8va display shift
  var displayMidi = midi;
  if (clefForShift === 'treble' && smrCurrentTextData && smrCurrentTextData.octaveShifts && typeof measureIdx === 'number') {
    var shifts = smrCurrentTextData.octaveShifts;
    for (var si = 0; si < shifts.length; si++) {
      var srange = shifts[si].measureRange;
      var midiMin = shifts[si].midiMin || 0;
      var startBeat = shifts[si].startBeat || 0;
      if (srange && measureIdx >= srange[0] && measureIdx <= srange[1] && midi >= midiMin && (typeof noteBeat !== 'number' || noteBeat >= startBeat)) {
        displayMidi = midi - 12;
        break;
      }
    }
  }
  var octave = Math.floor(displayMidi / 12) - 1;
  pc = displayMidi % 12;
  var flat = smrIsFlat(key);
  var name = flat ? SMR_NOTE_NAMES_FLAT[pc] : SMR_NOTE_NAMES_SHARP[pc];
  var acc = flat ? SMR_NOTE_ACCS_FLAT[pc] : SMR_NOTE_ACCS_SHARP[pc];
  var vfKey = name + (acc ? acc : '') + '/' + octave;
  var visibleAcc = explicitAcc || null;
  if (!visibleAcc) {
    var vfKey2 = smrKeyToVexflow(key);
    var keySharps = SMR_KEY_SIG_SHARPS[vfKey2] || [];
    var keyFlats = SMR_KEY_SIG_FLATS[vfKey2] || [];
    if (keySharps.length > 0) {
      var sharpLetterPCs = { 6:5, 1:0, 8:7, 3:2, 10:9, 5:4, 0:11 };
      for (var si2 = 0; si2 < keySharps.length; si2++) {
        if (pc === sharpLetterPCs[keySharps[si2]]) { visibleAcc = 'n'; break; }
      }
    }
    if (keyFlats.length > 0 && !visibleAcc) {
      var flatLetterPCs = { 10:11, 3:4, 8:9, 1:2, 6:7, 11:0, 4:5 };
      for (var fi = 0; fi < keyFlats.length; fi++) {
        if (pc === flatLetterPCs[keyFlats[fi]]) { visibleAcc = 'n'; break; }
      }
    }
  }
  return { key: vfKey, accidental: visibleAcc };
}

// ── Voice builders ──
function smrBuildAccidentals(notes, key, clef, measureIdx, mixedAccIds, shownAccidentals, group) {
  var keys = [], accs = [];
  for (var n = 0; n < group.length; n++) {
    var result = smrMidiToVexflow(group[n].midi, key, group[n].acc, measureIdx, clef, group[n].beat);
    keys.push(result.key);
    var acc = result.accidental;
    var noteId = result.key.replace(/(?<=^[a-g])(#|b)+(?=\/)/, '');
    if (!acc && mixedAccIds[noteId]) {
      var courtesyPC = group[n].midi % 12;
      var vfKeyC = smrKeyToVexflow(key);
      var ksharpsC = SMR_KEY_SIG_SHARPS[vfKeyC] || [];
      for (var kci = 0; kci < ksharpsC.length; kci++) {
        if (ksharpsC[kci] === courtesyPC) { acc = '#'; break; }
      }
      if (!acc) {
        var kflatsC = SMR_KEY_SIG_FLATS[vfKeyC] || [];
        for (var kcj = 0; kcj < kflatsC.length; kcj++) {
          if (kflatsC[kcj] === courtesyPC) { acc = 'b'; break; }
        }
      }
    }
    var cancelAcc = null;
    if (acc) {
      if (shownAccidentals[noteId] === acc) {
        acc = null;
      } else {
        var prev = shownAccidentals[noteId];
        if (prev === '##' && (acc === '#' || acc === 'n')) cancelAcc = 'n';
        else if (prev === 'bb' && (acc === 'b' || acc === 'n')) cancelAcc = 'n';
        shownAccidentals[noteId] = acc;
      }
    } else if (noteId in shownAccidentals && shownAccidentals[noteId] !== null) {
      var prev2 = shownAccidentals[noteId];
      var notePC2 = group[n].midi % 12;
      var vfKeyL = smrKeyToVexflow(key);
      var ksharps2 = SMR_KEY_SIG_SHARPS[vfKeyL] || [];
      var kflats2 = SMR_KEY_SIG_FLATS[vfKeyL] || [];
      var inKeyAcc = null;
      for (var ki2 = 0; ki2 < ksharps2.length; ki2++) { if (ksharps2[ki2] === notePC2) { inKeyAcc = '#'; break; } }
      if (!inKeyAcc) { for (var ki3 = 0; ki3 < kflats2.length; ki3++) { if (kflats2[ki3] === notePC2) { inKeyAcc = 'b'; break; } } }
      if (prev2 === '##' || prev2 === 'bb') cancelAcc = 'n';
      acc = inKeyAcc || 'n';
      shownAccidentals[noteId] = acc === 'n' ? null : acc;
    }
    accs.push({ acc: acc, cancel: cancelAcc });
  }
  return { keys: keys, accs: accs };
}

function smrPreScanMixedAccidentals(notes, key, clef, measureIdx) {
  var noteAccSets = {};
  for (var pi = 0; pi < notes.length; pi++) {
    var pResult = smrMidiToVexflow(notes[pi].midi, key, notes[pi].acc, measureIdx, clef, notes[pi].beat);
    var pId = pResult.key.replace(/(?<=^[a-g])(#|b)+(?=\/)/, '');
    var pAcc = pResult.accidental;
    if (!noteAccSets[pId]) noteAccSets[pId] = {};
    noteAccSets[pId][pAcc === null ? '__null__' : pAcc] = true;
  }
  var mixedAccIds = {};
  for (var mid in noteAccSets) {
    if (Object.keys(noteAccSets[mid]).length > 1) mixedAccIds[mid] = true;
  }
  return mixedAccIds;
}

function smrBuildVoiceNotes(notes, key, clef, measureIdx) {
  if (!VF) return [];
  notes = notes.slice().sort(function(a, b) { return a.beat - b.beat; });
  var groups = [];
  var lastBeat = -1;
  for (var i = 0; i < notes.length; i++) {
    if (groups.length > 0 && Math.abs(notes[i].beat - lastBeat) < 0.01) {
      groups[groups.length - 1].push(notes[i]);
    } else {
      groups.push([notes[i]]);
      lastBeat = notes[i].beat;
    }
  }
  var mixedAccIds = smrPreScanMixedAccidentals(notes, key, clef, measureIdx);
  var shownAccidentals = {};
  var vfNotes = [];
  for (var g = 0; g < groups.length; g++) {
    var group = groups[g];
    var dur = smrDurToVexflow(group[0].dur);
    var r = smrBuildAccidentals(notes, key, clef, measureIdx, mixedAccIds, shownAccidentals, group);
    var staveNote = new VF.StaveNote({ keys: r.keys, duration: dur, clef: clef || 'treble', auto_stem: true });
    for (var j = 0; j < r.accs.length; j++) {
      if (r.accs[j].acc) staveNote.addModifier(new VF.Accidental(r.accs[j].acc), j);
      if (r.accs[j].cancel) staveNote.addModifier(new VF.Accidental(r.accs[j].cancel), j);
    }
    vfNotes.push(staveNote);
  }
  return vfNotes;
}

function smrBuildVoiceWithRests(notes, key, clef, totalBeats, measureIdx) {
  if (!VF) return [];
  notes = notes.slice().sort(function(a, b) { return a.beat - b.beat; });
  var events = [];
  var lastBeat = -1;
  for (var i = 0; i < notes.length; i++) {
    if (events.length > 0 && Math.abs(notes[i].beat - lastBeat) < 0.01) {
      events[events.length - 1].notes.push(notes[i]);
    } else {
      events.push({ beat: notes[i].beat, dur: notes[i].dur, notes: [notes[i]] });
      lastBeat = notes[i].beat;
    }
  }
  var filled = [];
  var cursor = 0;
  if (events.length > 0 && events[0].beat > 0) {
    var gap = events[0].beat;
    var restDurs = smrFitRests(gap);
    for (var r = 0; r < restDurs.length; r++) {
      filled.push({ beat: cursor, dur: restDurs[r], rest: true });
      cursor += restDurs[r];
    }
  }
  for (var e = 0; e < events.length; e++) {
    var ev = events[e];
    if (ev.beat > cursor + 0.01) {
      var gap2 = ev.beat - cursor;
      var restDurs2 = smrFitRests(gap2);
      for (var r2 = 0; r2 < restDurs2.length; r2++) {
        filled.push({ beat: cursor, dur: restDurs2[r2], rest: true });
        cursor += restDurs2[r2];
      }
    }
    filled.push(ev);
    cursor = ev.beat + ev.dur;
  }
  if (cursor < totalBeats - 0.01) {
    var gap3 = totalBeats - cursor;
    var restDurs3 = smrFitRests(gap3);
    for (var r3 = 0; r3 < restDurs3.length; r3++) {
      filled.push({ beat: cursor, dur: restDurs3[r3], rest: true });
      cursor += restDurs3[r3];
    }
  }
  var restKey = clef === 'bass' ? 'd/3' : 'b/4';
  var mixedAccIds = smrPreScanMixedAccidentals(notes, key, clef, measureIdx);
  var shownAccidentals = {};
  var vfNotes = [];
  for (var f = 0; f < filled.length; f++) {
    var item = filled[f];
    var dur = smrDurToVexflow(item.dur);
    if (item.rest) {
      vfNotes.push(new VF.StaveNote({ keys: [restKey], duration: dur + 'r', clef: clef || 'treble' }));
    } else {
      var rr = smrBuildAccidentals(notes, key, clef, measureIdx, mixedAccIds, shownAccidentals, item.notes);
      var staveNote = new VF.StaveNote({ keys: rr.keys, duration: dur, clef: clef || 'treble', auto_stem: true });
      for (var j = 0; j < rr.accs.length; j++) {
        if (rr.accs[j].acc) staveNote.addModifier(new VF.Accidental(rr.accs[j].acc), j);
        if (rr.accs[j].cancel) staveNote.addModifier(new VF.Accidental(rr.accs[j].cancel), j);
      }
      vfNotes.push(staveNote);
    }
  }
  return vfNotes;
}

// ── Main VexFlow renderer ──
function smrRenderVexFlowInto(container) {
  if (!smrCurrentJson || !container || !VF) return;
  while (container.firstChild) container.removeChild(container.firstChild);

  var data = smrCurrentJson;
  var measures = data.measures;
  if (!measures || measures.length === 0) return;

  var layout = smrCurrentLayout || {};
  var systems = layout.systems || data.systems;
  var spacing = layout.staveSpacing || {};
  var h_row_default = spacing.h_row || spacing.trebleToBassGap || 125;
  var h_gap = spacing.h_gap || spacing.systemToSystemGap || 160;
  var h_row_matrix = layout.h_row || null;
  var lineHeight = h_row_default + h_gap;
  var leftMargin = spacing.leftMargin || 60;
  var firstSystemIndent = spacing.firstSystemIndent || 0;
  var rightMargin = spacing.rightMargin || 20;

  var timeSigParts = (data.timeSig || '4/4').split('/');
  var beatsPerMeasure = data.beatsPerMeasure || parseInt(timeSigParts[0]) || 4;
  var beatValue = parseInt(timeSigParts[1]) || 4;
  var quarterBeatsPerMeasure = beatsPerMeasure * (4 / beatValue);
  var totalBeats = beatsPerMeasure;

  var systemLayout = [];
  if (systems && systems.length > 0) {
    var idx = 0;
    for (var s = 0; s < systems.length; s++) {
      systemLayout.push({ startIdx: idx, count: systems[s] });
      idx += systems[s];
    }
  } else {
    var autoPerLine = 4;
    for (var ai = 0; ai < measures.length; ai += autoPerLine) {
      systemLayout.push({ startIdx: ai, count: Math.min(autoPerLine, measures.length - ai) });
    }
  }

  var n_rows = layout.n_rows || [];
  var n_pages = layout.n_pages || (n_rows.length || 1);
  var pageSize = layout.pageSize || {};
  var w_pdf = pageSize.w_pdf || 1241;
  var h_pdf = pageSize.h_pdf || 1754;
  var svgWidth = w_pdf;
  var titleOffset = pageSize.titleOffset || 279;
  var vfKey = smrKeyToVexflow(data.key);

  smrMeasurePositionMap = [];
  var globalBeatCursor = 0;
  var globalSysIdx = 0;

  for (var pageIdx = 0; pageIdx < n_pages; pageIdx++) {
    var pageRows = (n_rows.length > 0 && pageIdx < n_rows.length) ? n_rows[pageIdx] : systemLayout.length;
    var pageSystems = systemLayout.slice(globalSysIdx, globalSysIdx + pageRows);
    if (pageSystems.length === 0) continue;

    var pageContainer = document.createElement('div');
    pageContainer.style.cssText = 'margin:0;padding:0;line-height:0;font-size:0;';
    container.appendChild(pageContainer);

    var renderer = new VF.Renderer(pageContainer, VF.Renderer.Backends.SVG);
    renderer.resize(svgWidth, h_pdf);
    var context = renderer.getContext();
    context.setFont('Arial', 10);

    var pageTitleOffset = (pageIdx === 0) ? titleOffset : 40;
    var pageSystemYs = (layout.systemY && layout.systemY[pageIdx]) || null;

    for (var ps = 0; ps < pageSystems.length; ps++) {
      var sys = globalSysIdx + ps;
      var sysLayout = pageSystems[ps];
      var startIdx = sysLayout.startIdx;
      var endIdx = Math.min(startIdx + sysLayout.count, measures.length);
      var y = pageSystemYs ? pageSystemYs[ps] : (ps * lineHeight + pageTitleOffset);
      var trebleToBassGap = (h_row_matrix && h_row_matrix[pageIdx] && h_row_matrix[pageIdx][ps] != null) ? h_row_matrix[pageIdx][ps] : h_row_default;
      var sysLeftMargin = (sys === 0) ? leftMargin + firstSystemIndent : leftMargin;

      var measureXs = [];
      var measureWidths_arr = [];
      var w_clause = layout.w_clause || [];
      var rowWidths = w_clause[sys] || null;

      if (rowWidths && rowWidths.length === sysLayout.count) {
        var cx = sysLeftMargin;
        for (var wi = 0; wi < rowWidths.length; wi++) {
          measureXs.push(cx);
          measureWidths_arr.push(rowWidths[wi]);
          cx += rowWidths[wi];
        }
      } else {
        var firstMeasureExtra = 100;
        var lineStartExtra = 80;
        var isFirstMeasureInPiece = (startIdx === 0);
        var decoWidth = isFirstMeasureInPiece ? firstMeasureExtra : lineStartExtra;
        var availWidth = svgWidth - sysLeftMargin - rightMargin - decoWidth;
        var weights = [];
        var totalWeight = 0;
        for (var wi2 = startIdx; wi2 < endIdx; wi2++) {
          var m = measures[wi2];
          var noteCount = (m && m.notes) ? m.notes.length : 0;
          var w = Math.max(1, noteCount);
          weights.push(w); totalWeight += w;
        }
        var cx2 = sysLeftMargin;
        for (var mw = 0; mw < weights.length; mw++) {
          var w2 = Math.floor(availWidth * weights[mw] / totalWeight);
          if (mw === 0) w2 += decoWidth;
          measureXs.push(cx2); measureWidths_arr.push(w2); cx2 += w2;
        }
      }

      for (var i = startIdx; i < endIdx; i++) {
        var mi = i - startIdx;
        var x = measureXs[mi];
        var staveWidth = measureWidths_arr[mi];
        var isFirst = (i === 0);
        var isFirstInLine = (mi === 0);
        var staveKey = smrKeyToVexflow(smrGetActiveKey(i, data.key));

        var treble = new VF.Stave(x, y, staveWidth);
        if (isFirst) {
          var displayTimeSig = (data.timeSig === '4/4') ? 'C' : (data.timeSig || '4/4');
          treble.addClef('treble').addKeySignature(staveKey).addTimeSignature(displayTimeSig);
        } else if (isFirstInLine) {
          treble.addClef('treble').addKeySignature(staveKey);
        }
        treble.setContext(context).draw();

        var bass = new VF.Stave(x, y + trebleToBassGap, staveWidth);
        if (isFirst) {
          var displayTimeSig2 = (data.timeSig === '4/4') ? 'C' : (data.timeSig || '4/4');
          bass.addClef('bass').addKeySignature(staveKey).addTimeSignature(displayTimeSig2);
        } else if (isFirstInLine) {
          bass.addClef('bass').addKeySignature(staveKey);
        }
        bass.setContext(context).draw();

        if (isFirstInLine) {
          new VF.StaveConnector(treble, bass).setType('brace').setContext(context).draw();
          new VF.StaveConnector(treble, bass).setType('singleLeft').setContext(context).draw();
        }
        new VF.StaveConnector(treble, bass).setType('singleRight').setContext(context).draw();

        smrMeasurePositionMap.push({
          measureIdx: i, x: x, width: staveWidth, y: y,
          startBeat: globalBeatCursor, beatsPerMeasure: totalBeats, systemIdx: sys
        });
        globalBeatCursor += totalBeats;

        var measure = measures[i];
        if (!measure) continue;
        var trebleNotes = measure.notes.filter(function(n) { return n.clef === 'treble'; });
        var bassNotes = measure.notes.filter(function(n) { return n.clef === 'bass'; });

        var isPickup = !!measure.pickup;
        var trebleEmpty = trebleNotes.length === 0 && bassNotes.length > 0;
        var bassEmpty = bassNotes.length === 0 && trebleNotes.length > 0;
        var measureKey = smrGetActiveKey(i, data.key);
        var trebleVoiceNotes = trebleEmpty ? [] : (isPickup
          ? smrBuildVoiceNotes(trebleNotes, measureKey, 'treble', i)
          : smrBuildVoiceWithRests(trebleNotes, measureKey, 'treble', totalBeats, i));
        var bassVoiceNotes = bassEmpty ? [] : (isPickup
          ? smrBuildVoiceNotes(bassNotes, measureKey, 'bass', i)
          : smrBuildVoiceWithRests(bassNotes, measureKey, 'bass', totalBeats, i));

        try {
          var timeParts = (data.timeSig || '4/4').split('/');
          var beatDenom = parseInt(timeParts[1]) || 4;
          var trebleBeamGroups = [new VF.Fraction(1, beatDenom)];
          var hasSextuplets = bassNotes.length >= 6 && bassNotes.some(function(n) {
            return Math.abs(n.dur - 0.33) < 0.05;
          });
          var bassBeamGroups = [new VF.Fraction(2, 4)];

          if (trebleVoiceNotes.length > 0) {
            var tBeams = VF.Beam.generateBeams(trebleVoiceNotes, { groups: trebleBeamGroups });
            var voice = new VF.Voice({ num_beats: quarterBeatsPerMeasure, beat_value: 4 }).setStrict(false);
            voice.addTickables(trebleVoiceNotes);
            var trebleNoteWidth = (x + staveWidth) - treble.getNoteStartX() - 15;
            new VF.Formatter().joinVoices([voice]).format([voice], trebleNoteWidth);
            voice.draw(context, treble);
            for (var bi = 0; bi < tBeams.length; bi++) tBeams[bi].setContext(context).draw();
          }
          if (bassVoiceNotes.length > 0) {
            var bassTuplets = [];
            var manualBeams = [];
            if (hasSextuplets && bassNotes.length >= 6) {
              var singleNotes = [];
              for (var tn = 0; tn < bassVoiceNotes.length; tn++) {
                var bvn = bassVoiceNotes[tn];
                if (bvn.noteType === 'n' && bvn.getKeys().length === 1) singleNotes.push(bvn);
              }
              for (var rn = 0; rn < singleNotes.length; rn++) singleNotes[rn].setStemDirection(VF.Stem.DOWN);
              var remaining = singleNotes.slice();
              var firstGrp = remaining.length % 6;
              if (firstGrp > 0 && firstGrp < remaining.length) {
                var pickupGrp = remaining.splice(0, firstGrp);
                try { manualBeams.push(new VF.Beam(pickupGrp)); } catch(te) {}
              }
              while (remaining.length >= 6) {
                var grp = remaining.splice(0, 6);
                try {
                  bassTuplets.push(new VF.Tuplet(grp, { num_notes: 6, notes_occupied: 4, bracketed: false, ratioed: false }));
                  manualBeams.push(new VF.Beam(grp));
                } catch(te) {}
              }
            }
            var bBeams = manualBeams.length > 0 ? manualBeams : VF.Beam.generateBeams(bassVoiceNotes, { groups: bassBeamGroups });
            var voice2 = new VF.Voice({ num_beats: quarterBeatsPerMeasure, beat_value: 4 }).setStrict(false);
            voice2.addTickables(bassVoiceNotes);
            var bassNoteWidth = (x + staveWidth) - bass.getNoteStartX() - 15;
            new VF.Formatter().joinVoices([voice2]).format([voice2], bassNoteWidth);
            voice2.draw(context, bass);
            for (var bi2 = 0; bi2 < bBeams.length; bi2++) bBeams[bi2].setContext(context).draw();
          }
        } catch (e) {
          console.warn('VexFlow render error in measure ' + (i + 1) + ':', e.message);
        }
      }
    } // end system loop

    // Text annotations
    var svgEl = pageContainer.querySelector('svg');
    if (svgEl && smrCurrentTextData) {
      var ns = 'http://www.w3.org/2000/svg';
      if (pageIdx === 0 && smrCurrentTextData.pageAnnotations) {
        for (var pa = 0; pa < smrCurrentTextData.pageAnnotations.length; pa++) {
          var ann = smrCurrentTextData.pageAnnotations[pa];
          var textEl = document.createElementNS(ns, 'text');
          textEl.setAttribute('x', Math.round(ann.x));
          textEl.setAttribute('y', Math.round(ann.y));
          textEl.setAttribute('dominant-baseline', 'hanging');
          textEl.setAttribute('fill', (ann.style && ann.style.color) || 'currentColor');
          var anchor = ann.anchor === 'center' ? 'middle' : ann.anchor === 'right' ? 'end' : 'start';
          textEl.setAttribute('text-anchor', anchor);
          var fs = (ann.style && ann.style.fontSize) || 14;
          textEl.setAttribute('font-size', Math.round(fs * 2));
          textEl.setAttribute('font-weight', (ann.style && ann.style.fontWeight) || 'normal');
          textEl.setAttribute('font-style', (ann.style && ann.style.fontStyle) || 'normal');
          textEl.setAttribute('font-family', (ann.style && ann.style.fontFamily) || 'serif');
          textEl.textContent = ann.text;
          svgEl.appendChild(textEl);
        }
      }
      var pageFirstMeasure = pageSystems[0].startIdx;
      var pageLastMeasure = pageSystems[pageSystems.length - 1].startIdx + pageSystems[pageSystems.length - 1].count - 1;

      function smrFindPageMeasurePos(mIdx) {
        for (var si = 0; si < pageSystems.length; si++) {
          var sl = pageSystems[si];
          if (mIdx >= sl.startIdx && mIdx < sl.startIdx + sl.count) {
            var inRowIdx = mIdx - sl.startIdx;
            var gSys = globalSysIdx + si;
            var mY = pageSystemYs ? pageSystemYs[si] : (si * lineHeight + pageTitleOffset);
            var sysLM = (gSys === 0) ? leftMargin + firstSystemIndent : leftMargin;
            var w_clause_row = (layout.w_clause || [])[gSys] || null;
            var mX = sysLM, mW = 0;
            if (w_clause_row && w_clause_row.length === sl.count) {
              for (var wi = 0; wi < inRowIdx; wi++) mX += w_clause_row[wi];
              mW = w_clause_row[inRowIdx];
            } else {
              mX = sysLM + (inRowIdx * (svgWidth - sysLM - rightMargin) / sl.count);
              mW = (svgWidth - sysLM - rightMargin) / sl.count;
            }
            var rowHRow = (h_row_matrix && h_row_matrix[pageIdx] && h_row_matrix[pageIdx][si] != null) ? h_row_matrix[pageIdx][si] : h_row_default;
            return { x: mX, y: mY, width: mW, h_row: rowHRow };
          }
        }
        return null;
      }

      if (smrCurrentTextData.measureAnnotations) {
        for (var ma = 0; ma < smrCurrentTextData.measureAnnotations.length; ma++) {
          var mann = smrCurrentTextData.measureAnnotations[ma];
          if (mann.measure < pageFirstMeasure || mann.measure > pageLastMeasure) continue;
          if (mann.type === 'tuplet') continue;
          var textEl2 = document.createElementNS(ns, 'text');
          textEl2.setAttribute('x', Math.round(mann.x));
          textEl2.setAttribute('y', Math.round(mann.y));
          textEl2.setAttribute('dominant-baseline', 'hanging');
          textEl2.setAttribute('fill', 'currentColor');
          var mfs = (mann.style && mann.style.fontSize) || 12;
          if (mann.type === 'dynamics') mfs = mfs * 1.6;
          if (mann.type === 'technique') mfs = mfs * 2;
          textEl2.setAttribute('font-size', Math.round(mfs));
          textEl2.setAttribute('font-weight', (mann.type === 'dynamics') ? 'normal' : ((mann.style && mann.style.fontWeight) || 'normal'));
          textEl2.setAttribute('font-style', (mann.type === 'dynamics') ? 'italic' : ((mann.style && mann.style.fontStyle) || 'normal'));
          if (mann.type === 'dynamics') textEl2.setAttribute('font-family', "'Times New Roman', 'Georgia', serif");
          textEl2.textContent = mann.text;
          svgEl.appendChild(textEl2);
        }
      }
      if (smrCurrentTextData.octaveShifts && smrCurrentTextData.measureAnnotations) {
        for (var osi = 0; osi < smrCurrentTextData.octaveShifts.length; osi++) {
          var osRange = smrCurrentTextData.octaveShifts[osi].measureRange;
          if (!osRange) continue;
          var eightvaAnn = null;
          for (var oai = 0; oai < smrCurrentTextData.measureAnnotations.length; oai++) {
            var oa = smrCurrentTextData.measureAnnotations[oai];
            if (oa.text === '8va' && oa.measure === osRange[0]) { eightvaAnn = oa; break; }
          }
          if (!eightvaAnn || eightvaAnn.measure < pageFirstMeasure || eightvaAnn.measure > pageLastMeasure) continue;
          var endPos = smrFindPageMeasurePos(osRange[1]);
          if (!endPos) continue;
          var dottedLine = document.createElementNS(ns, 'line');
          dottedLine.setAttribute('x1', Math.round(eightvaAnn.x + 50));
          dottedLine.setAttribute('y1', Math.round(eightvaAnn.y + 5));
          dottedLine.setAttribute('x2', Math.round(endPos.x + endPos.width - 10));
          dottedLine.setAttribute('y2', Math.round(eightvaAnn.y + 5));
          dottedLine.setAttribute('stroke', 'currentColor');
          dottedLine.setAttribute('stroke-width', '2');
          dottedLine.setAttribute('stroke-dasharray', '6,4');
          svgEl.appendChild(dottedLine);
        }
      }
      if (smrCurrentTextData.pedalMarkings) {
        for (var pm = 0; pm < smrCurrentTextData.pedalMarkings.length; pm++) {
          var ped = smrCurrentTextData.pedalMarkings[pm];
          if (ped.page !== pageIdx + 1) continue;
          var pedEl = document.createElementNS(ns, 'text');
          pedEl.setAttribute('x', Math.round(ped.x));
          pedEl.setAttribute('y', Math.round(ped.y + 30));
          pedEl.setAttribute('dominant-baseline', 'hanging');
          pedEl.setAttribute('fill', 'currentColor');
          if (ped.type === 'ped') {
            pedEl.setAttribute('font-size', 21);
            pedEl.setAttribute('font-style', 'italic');
            pedEl.setAttribute('font-family', 'serif');
            pedEl.textContent = 'Ped.';
          } else {
            pedEl.setAttribute('font-size', 24);
            pedEl.textContent = '\u273B';
          }
          svgEl.appendChild(pedEl);
        }
      }
    }

    // viewBox scaling + dark theme recolor
    var finalSvg = pageContainer.querySelector('svg');
    if (finalSvg) {
      finalSvg.setAttribute('viewBox', '0 0 ' + svgWidth + ' ' + h_pdf);
      finalSvg.removeAttribute('width');
      finalSvg.removeAttribute('height');
      finalSvg.style.width = '100%';
      finalSvg.style.height = 'auto';
      finalSvg.style.display = 'block';
      finalSvg.style.background = 'transparent';
      // Invert to white for dark theme
      var els = finalSvg.querySelectorAll('path, text, line, rect');
      for (var ei = 0; ei < els.length; ei++) {
        var el = els[ei];
        var stroke = el.getAttribute('stroke');
        var fill = el.getAttribute('fill');
        if (stroke && stroke !== 'none' && stroke !== 'transparent') el.setAttribute('stroke', '#ffffff');
        if (fill && fill !== 'none' && fill !== 'transparent') el.setAttribute('fill', '#ffffff');
      }
      finalSvg.querySelectorAll('*').forEach(function(el) {
        var cs = getComputedStyle(el);
        if (cs.fill === 'rgb(0, 0, 0)') el.style.fill = '#ffffff';
        if (cs.stroke === 'rgb(0, 0, 0)') el.style.stroke = '#ffffff';
      });
    }

    globalSysIdx += pageRows;
  } // end page loop
}

// ── Playback (Tone.js) ──
function smrStartPlayback() {
  if (!smrCurrentJson || smrMeasurePositionMap.length === 0 || typeof Tone === 'undefined') return;
  Tone.start();
  var data = smrCurrentJson;
  var bpm = data.tempo || 120;
  smrPlaybackState.bpm = bpm;
  Tone.Transport.bpm.value = bpm;
  if (smrPlaybackState.playing) return;

  if (!smrPlaybackState.synth) {
    smrPlaybackState.synth = new Tone.PolySynth(Tone.Synth, {
      maxPolyphony: 32,
      voice: Tone.Synth,
      options: {
        oscillator: { type: 'triangle8' },
        envelope: { attack: 0.005, decay: 0.3, sustain: 0.4, release: 0.8 }
      }
    }).toDestination();
    smrPlaybackState.synth.volume.value = -6;
  }

  var lastMap = smrMeasurePositionMap[smrMeasurePositionMap.length - 1];
  smrPlaybackState.totalBeats = lastMap.startBeat + lastMap.beatsPerMeasure;
  var secondsPerBeat = 60 / bpm;
  smrPlaybackState.scheduledIds = [];

  for (var mi = 0; mi < data.measures.length; mi++) {
    var m = data.measures[mi];
    if (!m || !m.notes) continue;
    var posEntry = null;
    for (var pi = 0; pi < smrMeasurePositionMap.length; pi++) {
      if (smrMeasurePositionMap[pi].measureIdx === mi) { posEntry = smrMeasurePositionMap[pi]; break; }
    }
    if (!posEntry) continue;
    for (var ni = 0; ni < m.notes.length; ni++) {
      var note = m.notes[ni];
      var absTime = (posEntry.startBeat + note.beat) * secondsPerBeat;
      var durSec = note.dur * secondsPerBeat;
      var freq = Tone.Frequency(note.midi, 'midi').toFrequency();
      var vel = note.vel != null ? Math.max(0.05, note.vel / 127) : 0.7;
      var id = Tone.Transport.schedule(
        (function(f, d, v) { return function(time) {
          if (smrPlaybackState.synth) smrPlaybackState.synth.triggerAttackRelease(f, d, time, v);
        }; })(freq, Math.min(durSec, 4), vel),
        absTime
      );
      smrPlaybackState.scheduledIds.push(id);
    }
  }

  if (smrPlaybackState.pauseTime > 0) {
    Tone.Transport.start('+0', smrPlaybackState.pauseTime);
  } else {
    Tone.Transport.start('+0', 0);
  }
  smrPlaybackState.playing = true;
  smrPlaybackState.startTime = Tone.now() - (smrPlaybackState.pauseTime || 0);
  document.getElementById('smrBtnPlay').style.display = 'none';
  document.getElementById('smrBtnPause').style.display = '';
  document.getElementById('smrBtnStop').disabled = false;
  smrAnimateCursor();

  var totalDuration = smrPlaybackState.totalBeats * secondsPerBeat;
  Tone.Transport.schedule(function() { smrStopPlayback(); }, totalDuration + 0.1);
}

function smrPausePlayback() {
  if (!smrPlaybackState.playing) return;
  smrPlaybackState.pauseTime = Tone.Transport.seconds;
  Tone.Transport.pause();
  smrPlaybackState.playing = false;
  document.getElementById('smrBtnPlay').style.display = '';
  document.getElementById('smrBtnPause').style.display = 'none';
  if (smrPlaybackState.animFrame) cancelAnimationFrame(smrPlaybackState.animFrame);
}

function smrStopPlayback() {
  if (typeof Tone !== 'undefined') {
    Tone.Transport.stop();
    Tone.Transport.cancel();
  }
  smrPlaybackState.playing = false;
  smrPlaybackState.pauseTime = 0;
