  var svgContainer = document.getElementById('smrVexflowContainer');
  if (!svgContainer) return;
  var cursor = svgContainer.querySelector('#smr-playback-cursor');
  if (cursor) cursor.remove();
}

// ── Library browser ──
function loadSMRLibrary() {
  fetch('/api/smr/library').then(function(r) { return r.json(); }).then(function(data) {
    var el = document.getElementById('smrTree');
    el.innerHTML = '';
    smrRenderTree(data, el);
  }).catch(function() {
    document.getElementById('smrTree').innerHTML = '<div style="color:var(--text3);font-size:10px;padding:4px;">No sheets found — is SheetMusicReader running?</div>';
  });
}

function smrRenderTree(items, container) {
  for (var i = 0; i < items.length; i++) {
    var item = items[i];
    if (item.type === 'directory') {
      var dir = document.createElement('div');
      dir.className = 'smr-tree-dir';
      var label = document.createElement('div');
      label.className = 'smr-tree-dir-label';
      var arrow = document.createElement('span');
      arrow.className = 'arrow';
      arrow.textContent = '\u25BC';
      label.appendChild(arrow);
      var nameSpan = document.createElement('span');
      nameSpan.textContent = ' ' + item.name;
      label.appendChild(nameSpan);
      label.addEventListener('click', (function(d) { return function() { d.classList.toggle('collapsed'); }; })(dir));
      dir.appendChild(label);
      var children = document.createElement('div');
      children.className = 'smr-tree-children';
      if (item.children) smrRenderTree(item.children, children);
      dir.appendChild(children);
      container.appendChild(dir);
    } else {
      var file = document.createElement('div');
      file.className = 'smr-tree-file';
      file.setAttribute('data-path', item.path);
      var dots = document.createElement('span');
      dots.className = 'status-dots';
      var dotC = document.createElement('span');
      dotC.className = 'status-dot ' + (item.hasClaude ? 'claude' : 'pending');
      dotC.title = item.hasClaude ? 'Claude: converted' : 'Claude: pending';
      dots.appendChild(dotC);
      var dotG = document.createElement('span');
      dotG.className = 'status-dot ' + (item.hasGemini ? 'gemini' : 'pending');
      dotG.title = item.hasGemini ? 'Gemini: converted' : 'Gemini: pending';
      dots.appendChild(dotG);
      file.appendChild(dots);
      var fname = document.createElement('span');
      fname.textContent = item.name;
      file.appendChild(fname);
      file.addEventListener('click', (function(p, hc) {
        return function() { selectSMRFile(p, hc); };
      })(item.path, item.hasClaude));
      container.appendChild(file);
    }
  }
}

function selectSMRFile(filePath, hasJson) {
  smrCurrentFile = filePath;
  smrCurrentJson = null;
  smrCurrentLayout = null;
  smrCurrentTextData = null;
  smrStopPlayback();
  document.querySelectorAll('.smr-tree-file').forEach(function(f) { f.classList.remove('active'); });
  var active = document.querySelector('.smr-tree-file[data-path="' + CSS.escape(filePath) + '"]');
  if (active) active.classList.add('active');

  if (hasJson) {
    var jsonPath = filePath.replace(/\.[^.]+$/, '.json');
    var layoutPath = filePath.replace(/\.[^.]+$/, '.layout.json');
    var textPath = filePath.replace(/\.[^.]+$/, '.text.json');
    Promise.all([
      fetch('/api/smr/output/claude/' + jsonPath).then(function(r) { return r.ok ? r.json() : null; }).catch(function() { return null; }),
      fetch('/api/smr/output/claude/' + layoutPath).then(function(r) { return r.ok ? r.json() : null; }).catch(function() { return null; }),
      fetch('/api/smr/output/claude/' + textPath).then(function(r) { return r.ok ? r.json() : null; }).catch(function() { return null; })
    ]).then(function(results) {
      smrCurrentJson = results[0];
      smrCurrentLayout = results[1];
      smrCurrentTextData = results[2];
      if (smrCurrentJson) {
        smrRenderVexFlowInto(document.getElementById('smrVexflowContainer'));
        var info = document.getElementById('smrInfoBar');
        info.textContent = (smrCurrentJson.title || filePath) +
          (smrCurrentJson.key ? ' \u00B7 ' + smrCurrentJson.key : '') +
          (smrCurrentJson.tempo ? ' \u00B7 \u266A=' + smrCurrentJson.tempo : '') +
          (smrCurrentJson.timeSig ? ' \u00B7 ' + smrCurrentJson.timeSig : '');
        smrToggleView('svg');
      }
    });
  } else {
    // No JSON — show PDF if available
    document.getElementById('smrVexflowContainer').innerHTML = '<div style="color:var(--text3);font-size:10px;padding:8px;">No VexFlow data — select a converted file</div>';
    document.getElementById('smrInfoBar').textContent = filePath;
  }
}

function smrToggleView(mode) {
  smrViewMode = mode;
  var vf = document.getElementById('smrVexflowContainer');
  var pdf = document.getElementById('smrPdfContainer');
  var btnSvg = document.getElementById('smrBtnSvg');
  var btnPdf = document.getElementById('smrBtnPdf');
  if (mode === 'svg') {
    vf.style.display = '';
    pdf.style.display = 'none';
    btnSvg.classList.add('active');
    btnPdf.classList.remove('active');
  } else {
    vf.style.display = 'none';
    pdf.style.display = '';
    btnSvg.classList.remove('active');
    btnPdf.classList.add('active');
    // Render PDF if not already done
    if (pdf.children.length === 0 && smrCurrentFile && typeof pdfjsLib !== 'undefined') {
      smrRenderPdf(smrCurrentFile);
    }
  }
}

function smrRenderPdf(filePath) {
  var container = document.getElementById('smrPdfContainer');
  container.innerHTML = '<div style="color:var(--text3);font-size:10px;padding:8px;">Loading PDF...</div>';
  var pdfPath = '/api/smr/library-file/' + filePath;
  pdfjsLib.getDocument(pdfPath).promise.then(function(pdf) {
    container.innerHTML = '';
    for (var p = 1; p <= pdf.numPages; p++) {
      (function(pageNum) {
        pdf.getPage(pageNum).then(function(page) {
          var viewport = page.getViewport({ scale: 1.5 });
          var canvas = document.createElement('canvas');
          canvas.width = viewport.width;
          canvas.height = viewport.height;
          container.appendChild(canvas);
          page.render({ canvasContext: canvas.getContext('2d'), viewport: viewport });
        });
      })(p);
    }
  }).catch(function() {
    container.innerHTML = '<div style="color:var(--rose);font-size:10px;padding:8px;">Failed to load PDF</div>';
  });
}

function smrToggleTree() {
  var tree = document.getElementById('smrTree');
  var btn = document.getElementById('smrBtnTree');
  tree.classList.toggle('collapsed');
  btn.classList.toggle('active');
}

